/* ━━━ TOAST ━━━ */
function ToastItem({ toast, dispatch }) {
  const DURATION = 3500;
  const [progress, setProgress] = React.useState(100);
  React.useEffect(() => {
    const dismiss = setTimeout(() => dispatch({ type: "REMOVE_TOAST", payload: toast.id }), DURATION);
    const start = Date.now();
    const tick = setInterval(() => {
      const elapsed = Date.now() - start;
      setProgress(Math.max(0, 100 - (elapsed / DURATION) * 100));
    }, 50);
    return () => { clearTimeout(dismiss); clearInterval(tick); };
  }, [toast.id, dispatch]);

  const meta = {
    success: { color: T.success, bg: T.successBg, icon: <CheckCircle size={18} weight="fill" /> },
    error:   { color: T.danger,  bg: T.dangerBg,  icon: <XCircle size={18} weight="fill" /> },
    info:    { color: T.accent,  bg: T.accentLight, icon: <Sparkle size={18} weight="fill" /> },
  };
  const { color, bg, icon } = meta[toast.variant] || meta.info;

  return (
    <div className="scale-pop" style={{ borderRadius: T.r2, background: bg, boxShadow: T.shadow3, border: `1px solid ${color}25`, minWidth: 260, maxWidth: 340, overflow: "hidden", position: "relative" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "13px 16px 10px" }}>
        <span style={{ color, flexShrink: 0 }}>{icon}</span>
        <span style={{ fontSize: 13, fontWeight: 600, color, flex: 1, lineHeight: 1.4 }}>{toast.message}</span>
        <button onClick={() => dispatch({ type: "REMOVE_TOAST", payload: toast.id })} style={{ background: "none", border: "none", cursor: "pointer", padding: 2, color: color + "80", flexShrink: 0 }}>
          <X size={14} />
        </button>
      </div>
      {/* Progress bar */}
      <div style={{ height: 3, background: color + "20" }}>
        <div style={{ height: "100%", background: color, width: `${progress}%`, transition: "width 0.05s linear", borderRadius: 2 }} />
      </div>
    </div>
  );
}
function ToastContainer({ toasts, dispatch }) {
  if (!toasts || toasts.length === 0) return null;
  return (
    <div style={{ position: "fixed", bottom: 24, right: 24, zIndex: 10000, display: "flex", flexDirection: "column-reverse", gap: 8 }}>
      {toasts.map(t => <ToastItem key={t.id} toast={t} dispatch={dispatch} />)}
    </div>
  );
}

/* ━━━ FEATURE 1: LOTTIE CELEBRATION OVERLAY ━━━ */

// CSS burst animation for celebrations (replaces Lottie — saves ~900KB)
function BurstAnimation({ type }) {
  const color = type === "coins" ? "#D4A254" : type === "streak" ? "#818CF8" : "#22C55E";
  return (
    <div style={{ width: 120, height: 120, position: "relative" }}>
      <style>{`
        @keyframes burstRing { 0% { transform: scale(0); opacity: 1; } 100% { transform: scale(1.8); opacity: 0; } }
        @keyframes burstGlow { 0% { transform: scale(0.3); opacity: 0; } 30% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(0.9); opacity: 0.7; } }
        @keyframes burstSpin { 0% { transform: rotate(0deg) scale(0); } 40% { transform: rotate(120deg) scale(1.2); } 100% { transform: rotate(200deg) scale(0.85); opacity: 0.5; } }
      `}</style>
      <div style={{ position: "absolute", inset: 0, borderRadius: "50%", border: `3px solid ${color}`, animation: "burstRing 0.8s ease-out forwards" }} />
      <div style={{ position: "absolute", inset: 0, borderRadius: "50%", border: `2px solid ${color}88`, animation: "burstRing 0.8s ease-out 0.15s forwards", opacity: 0 }} />
      <div style={{ position: "absolute", inset: "15%", borderRadius: "50%", background: `radial-gradient(circle, ${color}33, transparent 70%)`, animation: "burstGlow 0.6s ease-out forwards" }} />
      {[0, 60, 120, 180, 240, 300].map(deg => (
        <div key={deg} style={{ position: "absolute", top: "50%", left: "50%", width: 6, height: 6, borderRadius: "50%", background: color, transform: `rotate(${deg}deg) translateY(-45px)`, animation: "burstSpin 0.7s ease-out forwards", animationDelay: `${deg / 1200}s` }} />
      ))}
    </div>
  );
}

// Canvas confetti particle system
function ConfettiCanvas({ active, duration = 2500, particleCount = 60 }) {
  const canvasRef = useRef(null);
  const particles = useRef([]);
  const animRef = useRef(null);
  const startTime = useRef(0);

  useEffect(() => {
    if (!active || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    startTime.current = Date.now();

    const colors = ["#D4A254", "#2D3A8C", "#22C55E", "#FB424E", "#7C3AED", "#0D9488", "#F59E0B", "#fff"];
    const shapes = ["rect", "circle", "star"];
    particles.current = Array.from({ length: particleCount }, () => ({
      x: canvas.width * 0.5 + (Math.random() - 0.5) * 200,
      y: canvas.height * 0.4,
      vx: (Math.random() - 0.5) * 14,
      vy: -Math.random() * 16 - 4,
      size: Math.random() * 8 + 4,
      color: colors[Math.floor(Math.random() * colors.length)],
      shape: shapes[Math.floor(Math.random() * shapes.length)],
      rotation: Math.random() * 360,
      rotSpeed: (Math.random() - 0.5) * 12,
      gravity: 0.35 + Math.random() * 0.15,
      opacity: 1,
    }));

    function draw() {
      const elapsed = Date.now() - startTime.current;
      if (elapsed > duration) { ctx.clearRect(0, 0, canvas.width, canvas.height); return; }
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const fadeStart = duration * 0.7;
      particles.current.forEach(p => {
        p.x += p.vx;
        p.vy += p.gravity;
        p.y += p.vy;
        p.vx *= 0.99;
        p.rotation += p.rotSpeed;
        p.opacity = elapsed > fadeStart ? Math.max(0, 1 - (elapsed - fadeStart) / (duration - fadeStart)) : 1;
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate((p.rotation * Math.PI) / 180);
        ctx.globalAlpha = p.opacity;
        ctx.fillStyle = p.color;
        if (p.shape === "rect") { ctx.fillRect(-p.size / 2, -p.size / 2, p.size, p.size * 0.6); }
        else if (p.shape === "circle") { ctx.beginPath(); ctx.arc(0, 0, p.size / 2, 0, Math.PI * 2); ctx.fill(); }
        else { // star
          ctx.beginPath();
          for (let i = 0; i < 5; i++) { const a = (i * 72 - 90) * Math.PI / 180; ctx.lineTo(Math.cos(a) * p.size / 2, Math.sin(a) * p.size / 2); const b = ((i * 72 + 36) - 90) * Math.PI / 180; ctx.lineTo(Math.cos(b) * p.size / 4, Math.sin(b) * p.size / 4); }
          ctx.closePath(); ctx.fill();
        }
        ctx.restore();
      });
      animRef.current = requestAnimationFrame(draw);
    }
    animRef.current = requestAnimationFrame(draw);
    return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
  }, [active, duration, particleCount]);

  if (!active) return null;
  return <canvas ref={canvasRef} style={{ position: "fixed", inset: 0, zIndex: 10001, pointerEvents: "none" }} />;
}

// Celebration overlay combining Lottie + confetti
function CelebrationOverlay({ type, onComplete }) {
  const [visible, setVisible] = useState(true);
  useEffect(() => {
    const t = setTimeout(() => { setVisible(false); onComplete?.(); }, type === "coins" ? 2200 : type === "streak" ? 3000 : 2500);
    return () => clearTimeout(t);
  }, [type, onComplete]);

  if (!visible) return null;

  const label = type === "coins" ? "Coins Earned!" : type === "streak" ? "Streak Milestone!" : type === "levelup" ? "Level Up!" : "Achievement!";
  const emoji = type === "coins" ? "🪙" : type === "streak" ? "🔥" : type === "levelup" ? "⭐" : "🏆";

  return (
    <>
      <ConfettiCanvas active={true} duration={type === "streak" ? 3000 : 2200} particleCount={type === "streak" ? 80 : 50} />
      <div style={{ position: "fixed", inset: 0, zIndex: 10002, display: "flex", alignItems: "center", justifyContent: "center", pointerEvents: "none" }}>
        <div className="scale-pop" style={{ textAlign: "center" }}>
          <div style={{ width: 120, height: 120, margin: "0 auto" }}>
            <BurstAnimation type={type} />
          </div>
          <div style={{ fontSize: 48, marginTop: -8 }}>{emoji}</div>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#fff", textShadow: "0 2px 12px rgba(0,0,0,0.5)", fontFamily: "'Bricolage Grotesque', sans-serif", marginTop: 4 }}>{label}</div>
        </div>
      </div>
    </>
  );
}

