/* ━━━ FEATURE 2: SHAREABLE PROGRESS CARD (html2canvas) ━━━ */

function ShareableProgressCard({ state }) {
  const cardRef = useRef(null);
  const [generating, setGenerating] = useState(false);
  const [showCard, setShowCard] = useState(false);
  const wallet = state.wallet;
  const gradedSubs = (state.submissions || []).filter(s => s.status === "graded");
  const exams = getExamCountdowns().slice(0, 2);

  // Compute readiness
  const totalHw = state.homework.filter(h => h.status === "active").length;
  const completedHw = (state.submissions || []).filter(s => s.status === "graded" || s.status === "submitted").length;
  const hwScore = totalHw > 0 ? Math.round((completedHw / Math.max(totalHw, 1)) * 100) : 50;
  const streakScore = Math.min(100, wallet.streak * 10);
  const coinScore = Math.min(100, wallet.coins / 5);
  const readiness = Math.round((hwScore + streakScore + coinScore) / 3);

  async function downloadCard() {
    if (!cardRef.current) return;
    setGenerating(true);
    try {
      const canvas = await html2canvas(cardRef.current, { backgroundColor: null, scale: 2, useCORS: true, logging: false });
      const link = document.createElement("a");
      link.download = `aworthy-progress-${new Date().toISOString().split("T")[0]}.png`;
      link.href = canvas.toDataURL("image/png");
      link.click();
    } catch (e) { console.error("Card generation failed:", e); }
    setGenerating(false);
  }

  async function shareCard() {
    if (!cardRef.current || !navigator.share) return downloadCard();
    setGenerating(true);
    try {
      const canvas = await html2canvas(cardRef.current, { backgroundColor: null, scale: 2, useCORS: true, logging: false });
      canvas.toBlob(async (blob) => {
        if (!blob) { setGenerating(false); return; }
        const file = new File([blob], "aworthy-progress.png", { type: "image/png" });
        await navigator.share({ title: "My A Worthy Progress", text: `Study streak: ${wallet.streak} days | Exam readiness: ${readiness}%`, files: [file] }).catch(() => {});
        setGenerating(false);
      }, "image/png");
    } catch (e) { downloadCard(); }
  }

  return (
    <div>
      <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
        <button onClick={() => setShowCard(!showCard)} style={{ padding: "8px 16px", borderRadius: T.r2, background: T.accentLight, color: T.accent, fontWeight: 700, fontSize: 12, border: `1px solid ${T.accent}22`, cursor: "pointer", display: "flex", alignItems: "center", gap: 6 }}>
          📸 {showCard ? "Hide" : "Preview"} Progress Card
        </button>
        {showCard && (
          <>
            <button onClick={downloadCard} disabled={generating} style={{ padding: "8px 16px", borderRadius: T.r2, background: T.accent, color: "#fff", fontWeight: 700, fontSize: 12, border: "none", cursor: generating ? "wait" : "pointer", display: "flex", alignItems: "center", gap: 6 }}>
              ⬇️ {generating ? "Generating..." : "Download"}
            </button>
            <button onClick={shareCard} disabled={generating} style={{ padding: "8px 16px", borderRadius: T.r2, background: T.navy, color: "#fff", fontWeight: 700, fontSize: 12, border: "none", cursor: generating ? "wait" : "pointer", display: "flex", alignItems: "center", gap: 6 }}>
              📤 Share
            </button>
          </>
        )}
      </div>

      {showCard && (
        <div ref={cardRef} style={{ width: 440, borderRadius: 20, overflow: "hidden", boxShadow: "0 8px 40px rgba(15,23,42,0.25)", fontFamily: "'Plus Jakarta Sans', sans-serif", marginBottom: 16 }}>
          {/* Card header */}
          <div style={{ background: "linear-gradient(135deg, #0F172A 0%, #1E2A4A 40%, #2D3A8C 100%)", padding: "28px 28px 22px", color: "#fff", position: "relative", overflow: "hidden" }}>
            <div style={{ position: "absolute", top: -30, right: -30, width: 120, height: 120, borderRadius: "50%", background: "radial-gradient(circle, rgba(212,162,84,0.15), transparent 70%)" }} />
            <div style={{ position: "absolute", bottom: -20, left: -20, width: 80, height: 80, borderRadius: "50%", background: "radial-gradient(circle, rgba(45,58,140,0.3), transparent 70%)" }} />
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16, position: "relative" }}>
              <div style={{ width: 36, height: 36, borderRadius: 8, background: "rgba(255,255,255,0.1)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, fontWeight: 800 }}>A</div>
              <div>
                <div style={{ fontSize: 14, fontWeight: 800, letterSpacing: 0.5 }}>A Worthy</div>
                <div style={{ fontSize: 9, color: "rgba(255,255,255,0.45)", letterSpacing: 1.5, textTransform: "uppercase" }}>Learning Platform</div>
              </div>
            </div>
            <div style={{ fontSize: 22, fontWeight: 800, fontFamily: "'Bricolage Grotesque', sans-serif", position: "relative" }}>My Progress</div>
            <div style={{ fontSize: 11, color: "rgba(255,255,255,0.5)", marginTop: 2, position: "relative" }}>{new Date().toLocaleDateString("en-SG", { day: "numeric", month: "long", year: "numeric" })}</div>
          </div>

          {/* Card body */}
          <div style={{ background: "#fff", padding: "22px 28px 28px" }}>
            {/* Stats row */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginBottom: 18 }}>
              {[
                { label: "Streak", value: `${wallet.streak}d`, icon: "🔥", color: "#2D3A8C" },
                { label: "Readiness", value: `${readiness}%`, icon: "🎯", color: readiness >= 70 ? "#22C55E" : readiness >= 40 ? "#F59E0B" : "#FB424E" },
                { label: "Coins", value: wallet.coins, icon: "🪙", color: "#D4A254" },
              ].map(s => (
                <div key={s.label} style={{ textAlign: "center", background: "#F8F7F4", borderRadius: 12, padding: "14px 8px" }}>
                  <div style={{ fontSize: 10, color: "#7A7A85", fontWeight: 600, marginBottom: 4 }}>{s.icon} {s.label}</div>
                  <div style={{ fontSize: 24, fontWeight: 800, color: s.color, fontFamily: "'Bricolage Grotesque', sans-serif" }}>{s.value}</div>
                </div>
              ))}
            </div>

            {/* Readiness bar */}
            <div style={{ marginBottom: 18 }}>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: "#7A7A85", fontWeight: 600, marginBottom: 4 }}>
                <span>Exam Readiness</span>
                <span>{readiness}%</span>
              </div>
              <div style={{ height: 10, background: "#EEEDF2", borderRadius: 8, overflow: "hidden" }}>
                <div style={{ height: "100%", borderRadius: 8, background: readiness >= 70 ? "linear-gradient(90deg, #22C55E, #16A34A)" : readiness >= 40 ? "linear-gradient(90deg, #F59E0B, #EAB308)" : "linear-gradient(90deg, #FB424E, #EF4444)", width: `${readiness}%` }} />
              </div>
            </div>

            {/* Upcoming exams */}
            {exams.length > 0 && (
              <div style={{ marginBottom: 14 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#1E1E2E", marginBottom: 6 }}>⏳ Next Exams</div>
                {exams.map((e, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "6px 0" }}>
                    <div style={{ fontSize: 16, fontWeight: 900, color: e.daysLeft <= 30 ? "#FB424E" : "#2D3A8C", fontFamily: "'JetBrains Mono', monospace", minWidth: 32, textAlign: "center" }}>{e.daysLeft}</div>
                    <div style={{ fontSize: 11, color: "#4A4A55" }}>{e.name} · <span style={{ color: "#7A7A85" }}>{e.date}</span></div>
                  </div>
                ))}
              </div>
            )}

            {/* Footer */}
            <div style={{ borderTop: "1px solid #EEEDF2", paddingTop: 12, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ fontSize: 9, color: "#AEAEB5", letterSpacing: 0.5 }}>lms.a-worthy.com</span>
              <span style={{ fontSize: 9, color: "#AEAEB5" }}>Homework graded: {gradedSubs.length}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ━━━ TIMER ━━━ */
function useTimer(totalMinutes, onEnd) {
  const [seconds, setSeconds] = useState(totalMinutes * 60);
  const [running, setRunning] = useState(false);
  const intervalRef = React.useRef(null);
  const start = useCallback(() => { clearInterval(intervalRef.current); setRunning(true); intervalRef.current = setInterval(() => { setSeconds((prev) => { if (prev <= 1) { clearInterval(intervalRef.current); setRunning(false); onEnd?.(); return 0; } return prev - 1; }); }, 1000); }, [onEnd]);
  const stop = useCallback(() => { clearInterval(intervalRef.current); setRunning(false); }, []);
  React.useEffect(() => () => clearInterval(intervalRef.current), []);
  const display = `${Math.floor(seconds / 60).toString().padStart(2, "0")}:${(seconds % 60).toString().padStart(2, "0")}`;
  return { seconds, display, running, start, stop };
}

/* ━━━ DOCUMENT VIEWER MODAL ━━━ */
function DocumentViewer({ resource, onClose }) {
  if (!resource) return null;
  const isPdf = resource.type === "pdf" || (resource.fileUrl && resource.fileUrl.endsWith(".pdf"));
  const isVideo = resource.type === "video";
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div onClick={onClose} style={{ position: "absolute", inset: 0, background: T.bgOverlay, backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }} />
      <div style={{ position: "relative", width: "90%", maxWidth: 1000, height: "88vh", background: T.bgCard, borderRadius: T.r4, display: "flex", flexDirection: "column", overflow: "hidden", boxShadow: T.shadow3 }}>
        <div style={{ padding: "14px 20px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ width: 36, height: 36, borderRadius: T.r2, background: resource.type === "pdf" ? T.dangerBg : resource.type === "video" ? "#DBEAFE" : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <FileIcon type={resource.type} />
            </div>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700, color: T.text }}>{resource.title}</div>
              <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 2 }}><SubjectBadge subjectId={resource.subject} small /><span style={{ fontSize: 11, color: T.textTer }}>{resource.topic}</span></div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            {resource.fileUrl && <a href={resource.fileUrl} download style={{ textDecoration: "none" }}><Btn variant="secondary" size="sm"><DownloadSimple size={14} weight="bold" /> Download</Btn></a>}
            {resource.fileUrl && isPdf && <a href={resource.fileUrl} target="_blank" rel="noopener noreferrer" style={{ textDecoration: "none" }}><Btn variant="secondary" size="sm"><ArrowSquareOut size={14} weight="bold" /> Open</Btn></a>}
            <button onClick={onClose} style={{ background: T.bgMuted, border: `1px solid ${T.border}`, borderRadius: T.r2, width: 34, height: 34, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}><X size={16} weight="bold" color={T.textSec} /></button>
          </div>
        </div>
        <div style={{ flex: 1, overflow: "hidden" }}>
          {isVideo && resource.videoUrl ? <iframe src={resource.videoUrl} style={{ width: "100%", height: "100%", border: "none" }} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen title={resource.title} /> :
           isPdf && resource.fileUrl ? <iframe src={resource.fileUrl} style={{ width: "100%", height: "100%", border: "none" }} title={resource.title} onError={e => { e.target.style.display = "none"; e.target.parentElement.querySelector(".fallback")?.style && (e.target.parentElement.querySelector(".fallback").style.display = "flex"); }} /> :
           null}
          {/* Fallback for all non-video files (DOCX, or PDF that failed to load) */}
          {(!isVideo || !resource.videoUrl) && !isPdf && resource.fileUrl ? (
            <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100%", gap: 16, padding: 40, textAlign: "center" }}>
              <div style={{ width: 80, height: 80, borderRadius: T.r4, background: T.accentLight, display: "flex", alignItems: "center", justifyContent: "center" }}><FileDoc size={36} /></div>
              <div style={{ fontSize: 18, fontWeight: 700, color: T.text }}>{resource.title}</div>
              <div style={{ fontSize: 13, color: T.textSec, lineHeight: 1.6, maxWidth: 400 }}>This document type can't be previewed directly in the browser. Download it to view in Microsoft Word, Google Docs, or your preferred application.</div>
              <div style={{ display: "flex", gap: 10, marginTop: 8 }}>
                <a href={resource.fileUrl} download style={{ textDecoration: "none" }}><Btn><DownloadSimple size={15} /> Download</Btn></a>
                <a href={`https://docs.google.com/gview?url=${encodeURIComponent(window.location.origin + resource.fileUrl)}&embedded=true`} target="_blank" rel="noopener noreferrer" style={{ textDecoration: "none" }}><Btn variant="secondary"><ArrowSquareOut size={15} /> Open in Google Docs</Btn></a>
              </div>
            </div>
          ) : (!isVideo && !isPdf) ? <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100%", gap: 12, color: T.textSec, padding: 40, textAlign: "center" }}>
              <Warning size={32} />
              <div style={{ fontSize: 15, fontWeight: 600 }}>File not available</div>
              <div style={{ fontSize: 13 }}>This resource file could not be loaded. It may not have been uploaded to the server yet.</div>
            </div> : null}
        </div>
      </div>
    </div>
  );
}

/* ━━━ GAMIFICATION COMPONENTS ━━━ */

function XPBar({ xp, compact }) {
  const lv = getLevel(xp);
  const progress = getLevelProgress(xp);
  const nextLv = LEVELS.find(l => l.level === lv.level + 1);
  if (compact) {
    return (
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <span style={{ fontSize: 11, fontWeight: 700, color: lv.color, background: lv.bg, padding: "3px 9px", borderRadius: 20, whiteSpace: "nowrap", flexShrink: 0 }}>{lv.emoji} {lv.name}</span>
        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: T.textTer, marginBottom: 3 }}>
            <span style={{ fontWeight: 700, color: lv.color }}>{xp} XP</span>
            {nextLv && <span>{nextLv.min} XP</span>}
          </div>
          <Progress value={progress} color={lv.color} bg={lv.bg} height={5} />
        </div>
      </div>
    );
  }
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontSize: 26 }}>{lv.emoji}</span>
          <div>
            <div style={{ fontWeight: 700, color: lv.color, fontSize: 15 }}>{lv.name}</div>
            <div style={{ fontSize: 11, color: T.textTer }}>Level {lv.level} of 5</div>
          </div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontWeight: 800, fontSize: 26, color: lv.color, fontFamily: "'JetBrains Mono', monospace", lineHeight: 1 }}>{xp}</div>
          <div style={{ fontSize: 11, color: T.textTer }}>XP earned</div>
        </div>
      </div>
      <Progress value={progress} color={lv.color} bg={lv.bg} height={10} />
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: T.textTer, marginTop: 5 }}>
        <span>{xp - lv.min} XP this level</span>
        {nextLv ? <span>{nextLv.min - xp} XP to {nextLv.emoji} {nextLv.name}</span> : <span style={{ color: lv.color, fontWeight: 700 }}>Max level reached!</span>}
      </div>
    </div>
  );
}

function BadgeChip({ badge, earned, size = "md" }) {
  const small = size === "sm";
  return (
    <div title={`${badge.name}: ${badge.desc}`} style={{ display: "inline-flex", alignItems: "center", gap: small ? 3 : 5, padding: small ? "4px 8px" : "6px 12px", borderRadius: T.r2, background: earned ? T.accentLight : T.bgMuted, border: `1px solid ${earned ? T.accentMid : T.border}`, opacity: earned ? 1 : 0.38, cursor: "default", transition: "all 0.15s" }}>
      <span style={{ fontSize: small ? 13 : 15 }}>{badge.emoji}</span>
      <span style={{ fontSize: small ? 10 : 11, fontWeight: earned ? 650 : 400, color: earned ? T.accentText : T.textTer }}>{badge.name}</span>
    </div>
  );
}

function StudentAvatar({ student, size = 40, radius = "50%" }) {
  const av = student?.avatar ? AVATAR_OPTIONS.find(a => a.id === student.avatar) : null;
  if (av) {
    return (
      <div style={{ width: size, height: size, borderRadius: radius, background: av.bg, border: `2.5px solid ${av.ring}66`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: Math.round(size * 0.52), flexShrink: 0, userSelect: "none" }}>
        {av.emoji}
      </div>
    );
  }
  const initials = (student?.name || "?").split(" ").map(n => n[0]).join("");
  return (
    <div style={{ width: size, height: size, borderRadius: radius, background: `linear-gradient(135deg, ${T.accent}, #3F51EC)`, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 800, fontSize: Math.round(size * 0.32), flexShrink: 0 }}>
      {initials}
    </div>
  );
}

function PodiumCard({ student, rank, xp }) {
  const lv = getLevel(xp);
  const podiumColors = { 1: "#F59E0B", 2: "#94A3B8", 3: "#CD7F32" };
  const podiumHeights = { 1: 100, 2: 70, 3: 55 };
  const medals = { 1: "🥇", 2: "🥈", 3: "🥉" };
  const c = podiumColors[rank];
  const isFirst = rank === 1;
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", width: isFirst ? 155 : 135, transform: isFirst ? "scale(1.05)" : "none", zIndex: isFirst ? 2 : 1 }}>
      {isFirst && <div style={{ fontSize: 22, marginBottom: 4 }}>👑</div>}
      <div style={{ boxShadow: isFirst ? `0 8px 28px ${c}66, 0 0 0 3px ${c}33` : `0 6px 20px ${c}55`, borderRadius: "50%", marginBottom: 6 }}>
        <StudentAvatar student={student} size={isFirst ? 58 : 50} />
      </div>
      <div style={{ textAlign: "center", marginBottom: 8 }}>
        <div style={{ fontWeight: 700, fontSize: isFirst ? 14 : 13, color: T.text }}>{student.name}</div>
        <div style={{ fontSize: 11, color: lv.color, fontWeight: 700 }}>{lv.emoji} {lv.name}</div>
        <div style={{ fontWeight: 800, fontSize: isFirst ? 19 : 17, color: c, fontFamily: "'JetBrains Mono', monospace", marginTop: 2 }}>{xp} XP</div>
      </div>
      <div style={{ width: "100%", height: podiumHeights[rank], background: isFirst ? `linear-gradient(to top, ${c}EE, ${c}88, ${c}55)` : `linear-gradient(to top, ${c}EE, ${c}88)`, borderRadius: `${T.r2}px ${T.r2}px 0 0`, display: "flex", alignItems: "flex-start", justifyContent: "center", paddingTop: 10, fontSize: isFirst ? 30 : 26, borderTop: `${isFirst ? 3 : 2}px solid ${c}`, borderLeft: `${isFirst ? 3 : 2}px solid ${c}`, borderRight: `${isFirst ? 3 : 2}px solid ${c}`, borderBottom: "none", boxShadow: isFirst ? `inset 0 2px 8px rgba(255,255,255,0.3)` : "none" }}>
        {medals[rank]}
      </div>
    </div>
  );
}

