/* ━━━ STUDY STREAK CALENDAR ━━━ */
function StreakCalendar({ wallet }) {
  // Build a 12-week (84-day) grid of activity
  const today = new Date();
  const days = [];
  for (let i = 83; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().split("T")[0];
    const claimed = wallet.history?.some(h => h.date === dateStr);
    days.push({ date: dateStr, active: claimed, day: d.getDay(), label: d.getDate() === 1 ? d.toLocaleString("default", { month: "short" }) : null });
  }
  // Group into weeks (columns)
  const weeks = [];
  let currentWeek = [];
  days.forEach((d, i) => {
    currentWeek.push(d);
    if (currentWeek.length === 7 || i === days.length - 1) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
  });

  return (
    <div style={{ background: T.bgCard, borderRadius: T.r3, padding: "20px 22px", border: `1px solid ${T.border}`, position: "relative", overflow: "hidden" }}>
      {/* Subtle decorative corner */}
      <div style={{ position: "absolute", top: -20, right: -20, width: 80, height: 80, borderRadius: "50%", background: "rgba(200,93,46,0.04)" }} />
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 16 }}>🔥</span>
          <div style={{ fontSize: 14, fontWeight: 700, color: T.text, fontFamily: "'Bricolage Grotesque', sans-serif" }}>Study Streak</div>
        </div>
        <div style={{ background: T.accentLight, borderRadius: 20, padding: "4px 12px", display: "flex", alignItems: "center", gap: 4 }}>
          <span style={{ fontSize: 14, fontWeight: 800, color: T.accent, fontFamily: "'JetBrains Mono', monospace" }}>{wallet.streak}</span>
          <span style={{ fontSize: 10, color: T.accentText, fontWeight: 500 }}>day{wallet.streak !== 1 ? "s" : ""}</span>
        </div>
      </div>
      {/* Month labels */}
      <div style={{ display: "flex", gap: 2, marginBottom: 3, paddingLeft: 0 }}>
        {weeks.map((week, wi) => {
          const monthLabel = week.find(d => d.label);
          return <div key={wi} style={{ width: 13, fontSize: 9, color: T.textTer, textAlign: "center", fontWeight: 600 }}>{monthLabel ? monthLabel.label : ""}</div>;
        })}
      </div>
      {/* Heatmap grid */}
      <div style={{ display: "flex", gap: 2 }}>
        {weeks.map((week, wi) => (
          <div key={wi} style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            {week.map((d, di) => (
              <div key={di} title={`${d.date}${d.active ? " — active" : ""}`}
                style={{ width: 13, height: 13, borderRadius: 3, background: d.active ? T.accent : T.bgMuted, opacity: d.active ? 1 : 0.4, transition: "all 0.2s ease", boxShadow: d.active ? "0 1px 3px rgba(200,93,46,0.2)" : "none" }} />
            ))}
          </div>
        ))}
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 10 }}>
        <span style={{ fontSize: 10, color: T.textTer }}>Last 12 weeks</span>
        <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 10, color: T.textTer }}>
          <span>Less</span>
          <div style={{ width: 11, height: 11, borderRadius: 3, background: T.bgMuted, opacity: 0.4 }} />
          <div style={{ width: 11, height: 11, borderRadius: 3, background: T.accent, opacity: 0.5 }} />
          <div style={{ width: 11, height: 11, borderRadius: 3, background: T.accent }} />
          <span>More</span>
        </div>
      </div>
    </div>
  );
}

/* ━━━ STUDENT DASHBOARD ━━━ */
function StudentDashboard({ state, dispatch }) {
  const today = new Date().toISOString().split("T")[0];
  const myHomework = state.homework.filter(h => h.status === "active");
  const mySubs = state.submissions;
  const pendingHw = myHomework.filter(h => {
    const sub = mySubs.find(s => s.homeworkId === h.id);
    return sub && sub.status !== "graded" && sub.status !== "submitted";
  });
  const gradedHw = mySubs.filter(s => s.status === "graded");

  return (
    <div>
      {/* Welcome — enhanced glassmorphism hero card */}
      {(() => {
        const hour = new Date().getHours();
        const greeting = hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";
        const greetEmoji = hour < 12 ? "🌅" : hour < 17 ? "☀️" : "🌙";
        const firstName = (state.user?.displayName || state.user?.email || "Scholar").split(" ")[0].split("@")[0];
        const pendingCount = myHomework.filter(h => !mySubs.find(s => s.homeworkId === h.id && (s.status === "graded" || s.status === "submitted"))).length;
        return (
          <div style={{ marginBottom: 24, background: "linear-gradient(135deg, #0F172A 0%, #1E2A4A 45%, #2D3A8C 100%)", borderRadius: T.r4, padding: "28px 24px 22px", position: "relative", overflow: "hidden" }}>
            {/* Background accents */}
            <div style={{ position: "absolute", inset: 0, background: "radial-gradient(circle at 80% 20%, rgba(212,162,84,0.14), transparent 50%), radial-gradient(circle at 10% 80%, rgba(79,91,213,0.1), transparent 50%)" }} />
            <div style={{ position: "absolute", top: -40, right: -40, width: 160, height: 160, borderRadius: "50%", border: "1px solid rgba(212,162,84,0.08)" }} />
            <div style={{ position: "absolute", top: -20, right: -20, width: 100, height: 100, borderRadius: "50%", border: "1px solid rgba(212,162,84,0.06)" }} />
            <div style={{ position: "absolute", bottom: -30, left: -20, width: 100, height: 100, borderRadius: "50%", background: "radial-gradient(circle, rgba(79,91,213,0.2), transparent 70%)" }} />

            {/* Content */}
            <div style={{ position: "relative", zIndex: 1 }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                <div style={{ fontSize: 10, fontWeight: 700, color: "#D4A254", textTransform: "uppercase", letterSpacing: 1.5, display: "flex", alignItems: "center", gap: 6 }}>
                  <span style={{ display: "inline-block", width: 6, height: 6, borderRadius: "50%", background: "#22C55E", boxShadow: "0 0 6px #22C55E" }} />
                  Student Dashboard
                </div>
                {pendingCount > 0 && (
                  <div style={{ fontSize: 10, fontWeight: 700, color: "#fff", background: "rgba(220,38,38,0.7)", padding: "3px 10px", borderRadius: 20, border: "1px solid rgba(220,38,38,0.4)" }}>
                    {pendingCount} pending
                  </div>
                )}
              </div>
              <h1 style={{ fontSize: 26, fontWeight: 800, color: "#fff", fontFamily: "'Bricolage Grotesque', sans-serif", margin: "0 0 4px", letterSpacing: "-0.03em" }}>
                {greetEmoji} {greeting}, {firstName}!
              </h1>
              <p style={{ fontSize: 13, color: "rgba(255,255,255,0.5)", margin: "0 0 18px", fontFamily: "'Fraunces', serif", fontStyle: "italic", fontWeight: 300 }}>
                {new Date().toLocaleDateString("en-SG", { weekday: "long", day: "numeric", month: "long" })} · Keep up the great work!
              </p>

              {/* Stat pills — 4 stats */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8 }}>
                {[
                  { value: state.wallet.coins, label: "Coins", emoji: "🪙", color: "#D4A254" },
                  { value: state.wallet.streak, label: "Streak", emoji: "🔥", color: "#818CF8" },
                  { value: gradedHw.length, label: "Graded", emoji: "✅", color: "#22C55E" },
                  { value: state.wallet.level || 1, label: "Level", emoji: "⭐", color: "#F59E0B" },
                ].map(stat => (
                  <div key={stat.label} style={{ background: "rgba(255,255,255,0.07)", backdropFilter: "blur(12px)", WebkitBackdropFilter: "blur(12px)", borderRadius: 12, padding: "12px 10px", border: "1px solid rgba(255,255,255,0.08)", textAlign: "center" }}>
                    <div style={{ fontSize: 22, fontWeight: 800, color: stat.color, fontFamily: "'Bricolage Grotesque', sans-serif", lineHeight: 1 }}>{stat.value}</div>
                    <div style={{ fontSize: 9, color: "rgba(255,255,255,0.4)", fontWeight: 600, marginTop: 4, letterSpacing: "0.05em" }}>{stat.emoji} {stat.label}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        );
      })()}

      {/* Exam Countdown */}
      {(() => {
        const exams = getExamCountdowns().slice(0, 3);
        return exams.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: T.text, marginBottom: 10, fontFamily: "'Bricolage Grotesque', sans-serif" }}>⏳ Exam Countdown</div>
            <div style={{ display: "flex", gap: 8 }}>
              {exams.map((e, i) => {
                const theme = T[e.subject] || T.eng;
                const urgent = e.daysLeft <= 30;
                return (
                  <div key={i} className="card-enter" style={{ "--i": i, flex: 1, background: urgent ? T.dangerBg : T.bgCard, borderRadius: T.r2, padding: "12px", border: `1px solid ${urgent ? T.danger + "33" : T.border}`, textAlign: "center" }}>
                    <div style={{ fontSize: 24, fontWeight: 900, color: urgent ? T.danger : theme.accent, fontFamily: "'JetBrains Mono', monospace" }}>{e.daysLeft}</div>
                    <div style={{ fontSize: 9, fontWeight: 600, color: T.textTer, textTransform: "uppercase" }}>days</div>
                    <div style={{ fontSize: 10, fontWeight: 600, color: T.text, marginTop: 4 }}>{e.name}</div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* Daily Challenge */}
      {(() => {
        const challenge = getDailyChallenge();
        const theme = T[challenge.subject] || T.eng;
        return (
          <div style={{ marginBottom: 20, background: "linear-gradient(135deg, #0F172A, #1E2A4A)", borderRadius: T.r3, padding: "18px 20px", position: "relative", overflow: "hidden" }}>
            <div style={{ position: "absolute", top: -10, right: -10, fontSize: 60, opacity: 0.06 }}>🎯</div>
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8 }}>
              <span style={{ fontSize: 12 }}>🎯</span>
              <span style={{ fontSize: 10, fontWeight: 700, color: "#D4A254", textTransform: "uppercase", letterSpacing: 1 }}>Daily Challenge</span>
              <span style={{ fontSize: 9, color: "rgba(255,255,255,0.3)", marginLeft: "auto", background: "rgba(255,255,255,0.06)", padding: "2px 8px", borderRadius: 10 }}>{challenge.type}</span>
            </div>
            <div style={{ fontSize: 13, color: "rgba(255,255,255,0.85)", lineHeight: 1.6 }}>{challenge.question}</div>
            <div style={{ fontSize: 10, color: "rgba(255,255,255,0.35)", marginTop: 8 }}>Complete for +10 coins · Refreshes daily</div>
          </div>
        );
      })()}

      {/* Word of the Day */}
      {(() => {
        const wotd = getWordOfTheDay();
        const theme = T[wotd.subject] || T.eng;
        return (
          <div style={{ marginBottom: 16, background: T.bgCard, borderRadius: T.r2, padding: "14px 16px", border: `1px solid ${T.border}`, borderLeft: `3px solid ${theme.accent}` }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: T.gold, textTransform: "uppercase", letterSpacing: 0.5 }}>📖 Word of the Day</span>
              <span style={{ fontSize: 9, color: T.textTer }}>{getSubject(wotd.subject)?.name}</span>
            </div>
            <div style={{ fontSize: 18, fontWeight: 800, color: T.text, fontFamily: "'Bricolage Grotesque', sans-serif" }}>{wotd.word}</div>
            <div style={{ fontSize: 12, color: T.textSec, marginTop: 2 }}>{wotd.def}</div>
            <div style={{ fontSize: 11, color: T.textTer, marginTop: 6, fontStyle: "italic", lineHeight: 1.5 }}>"{wotd.usage}"</div>
          </div>
        );
      })()}

      {/* Pomodoro Timer */}
      <div style={{ marginBottom: 20 }}>
        <PomodoroTimer dispatch={dispatch} />
      </div>

      {/* Streak Calendar */}
      <div style={{ marginBottom: 20 }}>
        <StreakCalendar wallet={state.wallet} />
      </div>

      {/* Pending homework */}
      {pendingHw.length > 0 && (
        <div style={{ marginBottom: 20 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: T.text, marginBottom: 10 }}>Homework Due</div>
          {pendingHw.map(h => (
            <div key={h.id} onClick={() => dispatch({ type: "SET_PAGE", payload: "homework" })}
              style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 14px", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: T.r2, marginBottom: 6, cursor: "pointer" }}>
              <span style={{ fontSize: 18 }}>📋</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 600, color: T.text }}>{h.title}</div>
                <div style={{ fontSize: 11, color: h.dueDate < today ? T.danger : T.textTer }}>Due {h.dueDate}{h.dueDate < today ? " — OVERDUE" : ""}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Recent grades */}
      {gradedHw.length > 0 && (
        <div style={{ marginBottom: 20 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: T.text, marginBottom: 10 }}>Recent Grades</div>
          {gradedHw.slice(0, 5).map(sub => {
            const hw = state.homework.find(h => h.id === sub.homeworkId);
            return (
              <div key={sub.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: T.r2, marginBottom: 4 }}>
                <div style={{ fontSize: 16, fontWeight: 800, color: T.success, fontFamily: "'Bricolage Grotesque', sans-serif", minWidth: 32 }}>{sub.grade}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: T.text }}>{hw?.title || "Homework"}</div>
                  {sub.gradeComment && <div style={{ fontSize: 11, color: T.textTer, marginTop: 2 }}>{sub.gradeComment.slice(0, 60)}...</div>}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Quick actions */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
        <div style={{ fontSize: 15, fontWeight: 700, color: T.text, fontFamily: "'Bricolage Grotesque', sans-serif" }}>Quick Actions</div>
        <div style={{ fontSize: 11, color: T.textTer, fontWeight: 500 }}>Jump right in</div>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(130px, 1fr))", gap: 10, marginBottom: 4 }}>
        {[
          { label: "Practice Drills", sub: "GP & English", page: "practice", icon: "🎯", bg: "linear-gradient(135deg, #FFF4EC, #FDE8D8)", border: "#F0DDD0", accent: "#EA580C" },
          { label: "Games", sub: "20+ games", page: "games-eng", icon: "🚀", bg: "linear-gradient(135deg, #EEF0FF, #DDE1FF)", border: "#C8CEFF", accent: "#4F5BD5" },
          { label: "Infographics", sub: "Visual notes", page: "infographics", icon: "✨", bg: "linear-gradient(135deg, #FFF8EC, #FEF0D0)", border: "#F0E8D0", accent: "#D97706" },
          { label: "Events", sub: "Prizes & more", page: "events", icon: "🎉", bg: "linear-gradient(135deg, #FFF0F0, #FFE0E0)", border: "#F0D8D8", accent: "#DC2626" },
          { label: "Community", sub: "Chat & share", page: "community", icon: "🤝", bg: "linear-gradient(135deg, #ECFAF2, #D4F5E4)", border: "#C0EDCE", accent: "#16A34A" },
        ].map((a, i) => (
          <button key={a.page} onClick={() => dispatch({ type: "SET_PAGE", payload: a.page })}
            className="card-lift card-enter"
            style={{ "--i": i, padding: "16px 12px", borderRadius: T.r3, background: a.bg, border: `1px solid ${a.border}`, cursor: "pointer", textAlign: "center", transition: "transform 0.15s ease, box-shadow 0.15s ease" }}
            onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = T.shadow3; }}
            onMouseLeave={e => { e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "none"; }}>
            <div style={{ fontSize: 26, marginBottom: 6 }}>{a.icon}</div>
            <div style={{ fontSize: 12, fontWeight: 700, color: T.text, marginBottom: 2 }}>{a.label}</div>
            <div style={{ fontSize: 10, color: T.textTer, fontWeight: 500 }}>{a.sub}</div>
          </button>
        ))}
      </div>

      {/* Study Plan */}
      <div style={{ marginTop: 20 }}>
        <div style={{ fontSize: 15, fontWeight: 700, color: T.text, marginBottom: 12, fontFamily: "'Bricolage Grotesque', sans-serif" }}>📅 Your Study Plan</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
          {generateStudyPlan(state).slice(0, 5).map((day, i) => {
            const theme = T[day.subjectId] || T.eng;
            return (
              <div key={i} className="card-enter" style={{ "--i": i, display: "flex", gap: 12, alignItems: "center", padding: "12px 14px", background: T.bgCard, borderRadius: T.r2, border: `1px solid ${T.border}`, borderLeft: `3px solid ${theme.accent}` }}>
                <div style={{ textAlign: "center", minWidth: 40 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, color: T.textTer }}>{day.day.slice(0, 3)}</div>
                  <div style={{ fontSize: 14, fontWeight: 800, color: T.text }}>{day.date.split(" ")[1]}</div>
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 12, fontWeight: 700, color: theme.accent }}>{day.subject}</div>
                  <div style={{ display: "flex", gap: 8, marginTop: 4 }}>
                    {day.tasks.map((t, j) => (
                      <span key={j} style={{ fontSize: 10, color: T.textSec, background: T.bgMuted, padding: "2px 8px", borderRadius: 10 }}>{t.icon} {t.type} · {t.duration}</span>
                    ))}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Weekly Progress Summary */}
      {(() => {
        const wp = getWeeklyProgress(state);
        return (
          <div style={{ marginTop: 20, background: T.bgCard, borderRadius: T.r3, padding: "18px 20px", border: `1px solid ${T.border}` }}>
            <div style={{ fontSize: 15, fontWeight: 700, color: T.text, marginBottom: 12, fontFamily: "'Bricolage Grotesque', sans-serif" }}>📊 This Week's Progress</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8 }}>
              {[
                { label: "Homework", value: wp.hwCompleted, icon: "📋", color: T.accent },
                { label: "Notes", value: wp.notesCreated, icon: "📝", color: T.teal },
                { label: "Reviews", value: wp.reviewsGiven, icon: "👀", color: T.success },
                { label: "Streak", value: `${wp.streakDays}d`, icon: "🔥", color: T.gold },
                { label: "Coins", value: `+${wp.coinsEarned}`, icon: "🪙", color: T.goldDark },
              ].map(s => (
                <div key={s.label} style={{ textAlign: "center", padding: "8px", borderRadius: T.r1, background: T.bgMuted }}>
                  <div style={{ fontSize: 18, fontWeight: 800, color: s.color, fontFamily: "'Bricolage Grotesque', sans-serif" }}>{s.value}</div>
                  <div style={{ fontSize: 10, color: T.textTer }}>{s.icon} {s.label}</div>
                </div>
              ))}
            </div>
          </div>
        );
      })()}

      {/* Shareable Progress Card */}
      <div style={{ marginTop: 20 }}>
        <ShareableProgressCard state={state} />
      </div>
    </div>
  );
}

function Dashboard({ state, dispatch }) {
  // If student role, show student dashboard
  if (state.role === "student") return <StudentDashboard state={state} dispatch={dispatch} />;

  const subjectProgress = SUBJECTS.map((s) => ({ ...s, progress: Math.floor(Math.random() * 40 + 30) }));
  const actIcons = { award: Trophy, upload: Upload, check: CheckCircle, play: Play, exam: Exam, plus: Plus };

  const pendingSubmissions = state.submissions.filter(s => s.status === "submitted").length;
  const activeHomework = state.homework.filter(h => h.status === "active").length;
  const todaySessions = state.sessions.filter(s => s.date === new Date().toISOString().split("T")[0]).length;

  return (
    <div>
      {/* 3D Hero Scene */}
      <HeroScene3D />

      {/* Tutor Hero Card */}
      <div style={{ borderRadius: T.r3, background: "linear-gradient(135deg, #0F172A 0%, #1E3A5F 50%, #2D3A8C 100%)", padding: "28px 32px", marginBottom: 24, position: "relative", overflow: "hidden" }}>
        {/* Decorative circles */}
        <div style={{ position: "absolute", top: -40, right: -40, width: 200, height: 200, borderRadius: "50%", background: "rgba(212,162,84,0.08)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", bottom: -60, right: 80, width: 160, height: 160, borderRadius: "50%", background: "rgba(45,58,140,0.3)", pointerEvents: "none" }} />
        <div style={{ position: "relative", zIndex: 1 }}>
          <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexWrap: "wrap", gap: 16 }}>
            <div>
              <div style={{ fontSize: 11, fontWeight: 700, color: T.gold, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 8, fontFamily: "'Bricolage Grotesque', sans-serif" }}>✦ The A-Worthy World</div>
              <h1 style={{ color: "#fff", fontSize: 30, fontWeight: 800, margin: "0 0 8px", letterSpacing: "-0.03em", fontFamily: "'Bricolage Grotesque', sans-serif", lineHeight: 1.15 }}>Welcome back, Creator J</h1>
              <p style={{ color: "rgba(255,255,255,0.6)", fontSize: 14, margin: 0, fontWeight: 300, fontFamily: "'Fraunces', serif", fontStyle: "italic" }}>Your students are waiting — let's make today count.</p>
            </div>
            {/* Alert pills */}
            <div style={{ display: "flex", flexDirection: "column", gap: 8, alignItems: "flex-end" }}>
              {pendingSubmissions > 0 && (
                <button onClick={() => dispatch({ type: "SET_PAGE", payload: "homework" })} style={{ display: "flex", alignItems: "center", gap: 6, background: "rgba(239,68,68,0.15)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 20, padding: "6px 14px", cursor: "pointer", color: "#FCA5A5", fontSize: 12, fontWeight: 700 }}>
                  <Bell size={13} weight="fill" />{pendingSubmissions} to grade
                </button>
              )}
              {activeHomework > 0 && (
                <button onClick={() => dispatch({ type: "SET_PAGE", payload: "homework" })} style={{ display: "flex", alignItems: "center", gap: 6, background: "rgba(251,191,36,0.15)", border: "1px solid rgba(251,191,36,0.3)", borderRadius: 20, padding: "6px 14px", cursor: "pointer", color: "#FDE68A", fontSize: 12, fontWeight: 700 }}>
                  <ClipboardText size={13} weight="fill" />{activeHomework} active tasks
                </button>
              )}
            </div>
          </div>
          {/* Quick action buttons */}
          <div style={{ display: "flex", gap: 10, marginTop: 22, flexWrap: "wrap" }}>
            {[
              { label: "Take Attendance", icon: CalendarCheck, page: "attendance", color: "#60A5FA" },
              { label: "Grade Homework", icon: ClipboardText, page: "homework", color: "#86EFAC" },
              { label: "View Progress", icon: ChartBar, page: "progress", color: "#C4B5FD" },
              { label: "Community", icon: Handshake, page: "community", color: T.gold },
            ].map(a => (
              <button key={a.label} onClick={() => dispatch({ type: "SET_PAGE", payload: a.page })} style={{ display: "flex", alignItems: "center", gap: 7, background: "rgba(255,255,255,0.08)", border: "1px solid rgba(255,255,255,0.12)", borderRadius: T.r2, padding: "9px 16px", cursor: "pointer", color: a.color, fontSize: 12, fontWeight: 700, transition: "all 0.15s", backdropFilter: "blur(4px)" }}
                onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.14)"; e.currentTarget.style.transform = "translateY(-1px)"; }}
                onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.08)"; e.currentTarget.style.transform = "none"; }}>
                <a.icon size={14} weight="duotone" />{a.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Stats — card grid with icon containers */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 12, marginBottom: 28 }}>
        {[
          { icon: FolderSimpleStar, value: state.resources.length, label: "Resources", color: T.accent, bg: T.accentLight, page: "library" },
          { icon: PlayCircle, value: state.videoLessons.length, label: "Videos", color: "#A85A38", bg: "#F6EAE4", page: "videos" },
          { icon: Lightning, value: state.quizzes.length, label: "Quizzes", color: "#C49030", bg: "#F6F0E0", page: "quizzes" },
          { icon: Users, value: state.students.length, label: "Students", color: "#4A8E9E", bg: "#E4EFF2", page: "progress" },
          { icon: CalendarCheck, value: state.sessions.length, label: "Sessions", color: "#3B6EA6", bg: "#E8EFF6", page: "attendance" },
          { icon: Handshake, value: (state.posts || []).length, label: "Community", color: "#2E8058", bg: "#E4F0EA", page: "community" },
        ].map((s, i) => (
          <div key={s.label} className="card-lift card-enter" style={{ "--i": i, cursor: "pointer", padding: "16px", background: T.bgCard, borderRadius: T.r2, border: `1px solid ${T.border}`, transition: "all 0.2s" }} onClick={() => dispatch({ type: "SET_PAGE", payload: s.page })}
            onMouseEnter={e => { e.currentTarget.style.borderColor = s.color + "60"; e.currentTarget.style.boxShadow = `0 4px 20px ${s.color}18`; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.boxShadow = "none"; }}>
            <div style={{ width: 36, height: 36, borderRadius: T.r2, background: s.bg, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 12 }}>
              <s.icon size={18} color={s.color} />
            </div>
            <div style={{ fontSize: 28, fontWeight: 800, color: T.text, fontFamily: "'Bricolage Grotesque', sans-serif", lineHeight: 1 }}>{s.value}</div>
            <div style={{ fontSize: 10, fontWeight: 500, color: T.textTer, marginTop: 4, letterSpacing: "0.08em", textTransform: "uppercase", fontFamily: "'Bricolage Grotesque', sans-serif" }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Subjects */}
      {/* Streak Calendar */}
      <div style={{ marginBottom: 24 }}>
        <StreakCalendar wallet={state.wallet} />
      </div>

      <h2 style={{ fontSize: 20, fontWeight: 800, color: T.text, margin: "0 0 16px", letterSpacing: "-0.03em", fontFamily: "'Bricolage Grotesque', sans-serif" }}>Your Subjects</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(230px, 1fr))", gap: 14, marginBottom: 28 }}>
        {subjectProgress.map((s, idx) => {
          const theme = getSubjectTheme(s.id);
          return (
            <Card key={s.id} className="card-enter card-lift" style={{ "--i": idx, padding: 0, overflow: "hidden" }} onClick={() => dispatch({ type: "SET_PAGE", payload: "library" })} elevated>
              {/* Subject illustration header */}
              <div style={{ position: "relative", overflow: "hidden" }}>
                <SubjectIllustration subject={s.id} size={240} />
                <div style={{ position: "absolute", top: 10, left: 14, display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 32, height: 32, borderRadius: T.r2, background: "rgba(255,255,255,0.9)", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 2px 8px rgba(0,0,0,0.1)" }}>
                    <BookOpen size={16} color={theme.accent} />
                  </div>
                  <span style={{ fontSize: 12, fontWeight: 800, color: theme.accent, background: "rgba(255,255,255,0.85)", padding: "2px 10px", borderRadius: 20, backdropFilter: "blur(4px)" }}>{TOPICS[s.id]?.length || 0} topics</span>
                </div>
              </div>
              <div style={{ padding: "14px 16px 16px" }}>
                <div style={{ fontSize: 15, fontWeight: 700, color: T.text, marginBottom: 8 }}>{s.name}</div>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: T.textSec, marginBottom: 6 }}>
                  <span>Progress</span><span style={{ color: theme.accent, fontWeight: 700 }}>{s.progress}%</span>
                </div>
                <Progress value={s.progress} color={theme.accent} bg={theme.bg} />
              </div>
            </Card>
          );
        })}
      </div>

      {/* Today's Classes */}
      {(() => {
        const todayClasses = state.sessions.filter(s => s.date === "2026-03-18");
        if (todayClasses.length === 0) return null;
        return (
          <div style={{ marginBottom: 28 }}>
            <h2 style={{ fontSize: 20, fontWeight: 800, color: T.text, margin: "0 0 16px", letterSpacing: "-0.03em", fontFamily: "'Bricolage Grotesque', sans-serif" }}>Today's Classes</h2>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 14 }}>
              {todayClasses.map(session => {
                const theme = getSubjectTheme(session.subject);
                const students = state.students.filter(st => st.subjects.includes(session.subject));
                const rec = state.attendance[session.id] || {};
                const marked = Object.keys(rec).length;
                return (
                  <Card key={session.id} onClick={() => dispatch({ type: "SET_PAGE", payload: "attendance" })} elevated style={{ borderLeft: `3px solid ${theme.accent}` }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}>
                      <div style={{ width: 40, height: 40, borderRadius: T.r2, background: theme.bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <CalendarCheck size={20} weight="duotone" color={theme.accent} />
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 14, fontWeight: 650, color: T.text }}>{getSubject(session.subject)?.name}</div>
                        <div style={{ fontSize: 12, color: T.textTer }}>{session.time}</div>
                      </div>
                      {marked < students.length ? (
                        <Badge color={T.warning} bg={T.warningBg}>{students.length - marked} unmarked</Badge>
                      ) : (
                        <Badge color={T.success} bg={T.successBg}><CheckCircle size={12} weight="fill" /> Done</Badge>
                      )}
                    </div>
                    {session.notes && <div style={{ fontSize: 12, color: T.textSec, background: T.bgMuted, padding: "6px 10px", borderRadius: T.r1 }}>{session.notes}</div>}
                    {!session.notes && <div style={{ fontSize: 12, color: T.textTer, fontStyle: "italic" }}>Click to take attendance</div>}
                  </Card>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* Class Standings + Community Preview */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", gap: 20, marginBottom: 28 }}>
        <Card elevated style={{ padding: 22 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 18 }}>
            <h3 style={{ fontSize: 16, fontWeight: 800, color: T.text, margin: 0, fontFamily: "'Bricolage Grotesque', sans-serif", letterSpacing: "-0.02em" }}>🏆 Class Standings</h3>
            <button onClick={() => dispatch({ type: "SET_PAGE", payload: "leaderboard" })} style={{ background: T.accentLight, border: "none", borderRadius: 20, padding: "5px 14px", fontSize: 11, fontWeight: 700, color: T.accentText, cursor: "pointer", transition: "all 0.15s" }}>Full Leaderboard →</button>
          </div>
          {[...state.students].map(s => ({ ...s, xp: calcStudentXP(s, state) })).sort((a, b) => b.xp - a.xp).map((student, idx) => {
            const lv = getLevel(student.xp);
            const rankIcon = ["🥇", "🥈", "🥉"][idx] || `#${idx + 1}`;
            return (
              <div key={student.id} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: idx < state.students.length - 1 ? 14 : 0 }}>
                <span style={{ width: 24, fontSize: idx < 3 ? 18 : 12, textAlign: "center" }}>{rankIcon}</span>
                <StudentAvatar student={student} size={32} />
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
                    <span style={{ fontSize: 12, fontWeight: 650, color: T.text }}>{student.name}</span>
                    <span style={{ fontSize: 11, fontWeight: 700, color: lv.color, fontFamily: "'JetBrains Mono', monospace" }}>{student.xp} XP</span>
                  </div>
                  <Progress value={getLevelProgress(student.xp)} color={lv.color} bg={lv.bg} height={4} />
                </div>
              </div>
            );
          })}
        </Card>

        <Card elevated style={{ padding: 22 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 18 }}>
            <h3 style={{ fontSize: 16, fontWeight: 800, color: T.text, margin: 0, fontFamily: "'Bricolage Grotesque', sans-serif", letterSpacing: "-0.02em" }}>💬 Community</h3>
            <button onClick={() => dispatch({ type: "SET_PAGE", payload: "community" })} style={{ background: T.accentLight, border: "none", borderRadius: 20, padding: "5px 14px", fontSize: 11, fontWeight: 700, color: T.accentText, cursor: "pointer", transition: "all 0.15s" }}>View All →</button>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {(state.posts || []).slice(0, 3).map(post => (
              <div key={post.id} onClick={() => dispatch({ type: "SET_PAGE", payload: "community" })} style={{ cursor: "pointer", padding: "10px 12px", borderRadius: T.r2, border: `1px solid ${T.border}`, background: T.bgMuted, transition: "all 0.15s" }}
                onMouseEnter={e => e.currentTarget.style.background = T.bgHover}
                onMouseLeave={e => e.currentTarget.style.background = T.bgMuted}>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 3 }}>
                  {post.isAnnouncement && <span style={{ fontSize: 10, fontWeight: 700, color: "#92400E", background: "#FEF3C7", padding: "1px 5px", borderRadius: 20 }}>📢</span>}
                  <span style={{ fontSize: 12, fontWeight: 650, color: T.text }}>{post.title}</span>
                </div>
                <div style={{ fontSize: 11, color: T.textTer }}>{post.author} · {post.comments.length} comments</div>
              </div>
            ))}
          </div>
        </Card>
      </div>

      {/* Activity + Quick Actions */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", gap: 20 }}>
        <Card elevated style={{ padding: 24 }}>
          <h3 style={{ fontSize: 15, fontWeight: 700, color: T.text, margin: "0 0 18px" }}>Recent Activity</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            {ACTIVITY_FEED.map((a) => {
              const Icon = actIcons[a.type] || BookOpen;
              return (
                <div key={a.id} style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                  <div style={{ width: 32, height: 32, borderRadius: T.r1, background: T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    <Icon size={15} weight="duotone" color={T.accent} />
                  </div>
                  <div>
                    <div style={{ fontSize: 13, color: T.text, lineHeight: 1.5 }}>{a.text}</div>
                    <div style={{ fontSize: 11, color: T.textTer, marginTop: 2 }}>{a.time}</div>
                  </div>
                </div>
              );
            })}
          </div>
        </Card>

        <Card elevated style={{ padding: 24 }}>
          <h3 style={{ fontSize: 15, fontWeight: 700, color: T.text, margin: "0 0 18px" }}>Quick Actions</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {[{ label: "Take Attendance", icon: CalendarCheck, page: "attendance", color: "#3F51EC" },
              { label: "Upload New Resource", icon: Upload, page: "library", color: "#0C8CE9" },
              { label: "Create a Quiz", icon: Lightning, page: "quizzes", color: "#6660B9" },
              { label: "View Student Progress", icon: ChartLineUp, page: "progress", color: "#00A85A" },
              { label: "Start Mock Exam", icon: Target, page: "exams", color: "#E07800" }
            ].map((item) => (
                <button key={item.label} onClick={() => dispatch({ type: "SET_PAGE", payload: item.page })}
                  onMouseEnter={(e) => e.currentTarget.style.background = T.bgHover}
                  onMouseLeave={(e) => e.currentTarget.style.background = T.bgMuted}
                  style={{ display: "flex", alignItems: "center", gap: 12, padding: "11px 14px", background: T.bgMuted, borderRadius: T.r2, border: "none", cursor: "pointer", transition: "all 0.15s", width: "100%", textAlign: "left" }}>
                  <div style={{ width: 32, height: 32, borderRadius: T.r1, background: item.color + "14", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    <item.icon size={16} weight="duotone" color={item.color} />
                  </div>
                  <span style={{ fontSize: 13, fontWeight: 600, color: T.text }}>{item.label}</span>
                  <CaretRight size={14} weight="bold" color={T.textTer} style={{ marginLeft: "auto" }} />
                </button>
              ))}
          </div>
        </Card>
      </div>
    </div>
  );
}

function ContentLibrary({ state, dispatch }) {
  const [search, setSearch] = useState("");
  const [showUpload, setShowUpload] = useState(false);
  const [viewingResource, setViewingResource] = useState(null);
  const [nT, snT] = useState(""); const [nS, snS] = useState(""); const [nTo, snTo] = useState(""); const [nTy, snTy] = useState("pdf");
  // Navigation: null = all subjects view, "eng" = subject view, { subject: "eng", topic: "Comprehension" } = topic view
  const [nav, setNav] = useState(null);
  // Track which subject folders are expanded in the sidebar
  const [expandedSubjects, setExpandedSubjects] = useState({});

  function toggleSubject(id) { setExpandedSubjects((prev) => ({ ...prev, [id]: !prev[id] })); }

  // Compute resource counts
  function countBySubject(subjectId) { return state.resources.filter((r) => r.subject === subjectId).length; }
  function countByTopic(subjectId, topic) { return state.resources.filter((r) => r.subject === subjectId && r.topic === topic).length; }

  // Filtered resources based on current navigation + search
  const filtered = state.resources.filter((r) => {
    if (search && !r.title.toLowerCase().includes(search.toLowerCase())) return false;
    if (nav && typeof nav === "string") { if (r.subject !== nav) return false; }
    if (nav && typeof nav === "object") { if (r.subject !== nav.subject || r.topic !== nav.topic) return false; }
    return true;
  });

  function handleUpload() {
    if (!nT || !nS || !nTo) return;
    dispatch({ type: "ADD_RESOURCE", payload: { title: nT, subject: nS, topic: nTo, type: nTy } });
    dispatch({ type: "ADD_TOAST", payload: { message: `"${nT}" uploaded`, variant: "success" } });
    snT(""); snS(""); snTo(""); snTy("pdf"); setShowUpload(false);
  }
  const isBookmarked = (id) => state.bookmarks.includes(id);

  // Breadcrumb
  const breadcrumbs = [];
  breadcrumbs.push({ label: "All Subjects", onClick: () => setNav(null) });
  if (nav) {
    const subjId = typeof nav === "string" ? nav : nav.subject;
    const subj = getSubject(subjId);
    breadcrumbs.push({ label: subj?.name || subjId, onClick: () => setNav(subjId) });
    if (typeof nav === "object" && nav.topic) {
      breadcrumbs.push({ label: nav.topic, onClick: null });
    }
  }

  // Current title/subtitle
  let pageTitle = "Content Library";
  let pageSubtitle = `${state.resources.length} resources across ${SUBJECTS.length} subjects`;
  if (nav && typeof nav === "string") {
    const subj = getSubject(nav);
    pageTitle = subj?.name || nav;
    const count = countBySubject(nav);
    pageSubtitle = `${count} resource${count !== 1 ? "s" : ""} · ${(TOPICS[nav] || []).length} topics`;
  }
  if (nav && typeof nav === "object") {
    pageTitle = nav.topic;
    const count = countByTopic(nav.subject, nav.topic);
    const subj = getSubject(nav.subject);
    pageSubtitle = `${count} resource${count !== 1 ? "s" : ""} in ${subj?.name || nav.subject}`;
  }

  return (
    <div>
      {viewingResource && <DocumentViewer resource={viewingResource} onClose={() => setViewingResource(null)} />}

      <PageHeader title={pageTitle} subtitle={pageSubtitle} action={<Btn onClick={() => setShowUpload(!showUpload)}><Plus size={15} weight="bold" /> Upload Resource</Btn>} />

      {/* Breadcrumb */}
      {nav && (
        <div style={{ display: "flex", alignItems: "center", gap: 4, marginBottom: 16, flexWrap: "wrap" }}>
          {breadcrumbs.map((bc, i) => (
            <React.Fragment key={i}>
              {i > 0 && <CaretRight size={12} weight="bold" color={T.textTer} />}
              {bc.onClick ? (
                <button onClick={bc.onClick} style={{ background: "none", border: "none", cursor: "pointer", color: i === breadcrumbs.length - 1 ? T.text : T.accent, fontSize: 13, fontWeight: 600, padding: "2px 4px", borderRadius: T.r1 }}
                  onMouseEnter={(e) => { if (bc.onClick) e.currentTarget.style.background = T.bgHover; }}
                  onMouseLeave={(e) => e.currentTarget.style.background = "none"}>
                  {bc.label}
                </button>
              ) : (
                <span style={{ fontSize: 13, fontWeight: 600, color: T.text, padding: "2px 4px" }}>{bc.label}</span>
              )}
            </React.Fragment>
          ))}
        </div>
      )}

      {showUpload && (
        <Card elevated style={{ marginBottom: 20, borderLeft: `3px solid ${T.accent}` }}>
          <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Upload New Resource</h3>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 14 }}>
            <Input value={nT} onChange={snT} placeholder="Resource title" />
            <Select value={nTy} onChange={snTy} options={[{ value: "pdf", label: "PDF" }, { value: "docx", label: "DOCX" }, { value: "video", label: "Video" }]} />
            <Select value={nS} onChange={snS} options={SUBJECTS.map((s) => ({ value: s.id, label: s.name }))} placeholder="Select subject" />
            <Select value={nTo} onChange={snTo} options={(TOPICS[nS] || []).map((t) => ({ value: t, label: t }))} placeholder="Select topic" />
          </div>
          <div style={{ display: "flex", gap: 8 }}><Btn onClick={handleUpload}><Upload size={14} weight="bold" /> Upload</Btn><Btn onClick={() => setShowUpload(false)} variant="secondary"><X size={14} weight="bold" /> Cancel</Btn></div>
        </Card>
      )}

      <div style={{ display: "flex", gap: 20 }}>
        {/* Sidebar folder tree */}
        <div style={{ width: 240, flexShrink: 0 }}>
          <Card elevated style={{ padding: 0, overflow: "hidden" }}>
            {/* Sidebar header */}
            <div style={{ padding: "14px 16px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", gap: 8 }}>
              <FolderSimple size={16} weight="duotone" color={T.accent} />
              <span style={{ fontSize: 12, fontWeight: 700, color: T.text, letterSpacing: 0.2, textTransform: "uppercase" }}>Folders</span>
            </div>

            {/* All Subjects root */}
            <button onClick={() => setNav(null)}
              onMouseEnter={(e) => { if (nav !== null) e.currentTarget.style.background = T.bgHover; }}
              onMouseLeave={(e) => { if (nav !== null) e.currentTarget.style.background = "transparent"; }}
              style={{ display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "10px 16px", border: "none", cursor: "pointer", background: nav === null ? T.accentLight : "transparent", color: nav === null ? T.accentText : T.text, fontSize: 13, fontWeight: nav === null ? 650 : 500, transition: "all 0.15s", boxShadow: nav === null ? `inset 3px 0 0 ${T.accent}` : "none" }}>
              <Books size={16} weight={nav === null ? "duotone" : "regular"} />
              All Subjects
              <span style={{ marginLeft: "auto", fontSize: 11, color: T.textTer, fontWeight: 600 }}>{state.resources.length}</span>
            </button>

            <div style={{ height: 1, background: T.border, margin: "4px 12px" }} />

            {/* Subject folders */}
            {SUBJECTS.map((subj) => {
              const theme = getSubjectTheme(subj.id);
              const isExpanded = expandedSubjects[subj.id];
              const isActiveSubject = nav === subj.id || (typeof nav === "object" && nav?.subject === subj.id);
              const topics = TOPICS[subj.id] || [];
              const subjCount = countBySubject(subj.id);
              return (
                <div key={subj.id}>
                  <div style={{ display: "flex", alignItems: "center" }}>
                    {/* Expand/collapse toggle */}
                    <button onClick={() => toggleSubject(subj.id)}
                      style={{ background: "none", border: "none", cursor: "pointer", padding: "0 4px 0 12px", display: "flex", alignItems: "center" }}>
                      <CaretRight size={12} weight="bold" color={T.textTer}
                        style={{ transform: isExpanded ? "rotate(90deg)" : "none", transition: "transform 0.15s" }} />
                    </button>
                    {/* Subject folder button */}
                    <button onClick={() => { setNav(subj.id); if (!expandedSubjects[subj.id]) toggleSubject(subj.id); }}
                      onMouseEnter={(e) => { if (!isActiveSubject || typeof nav === "object") e.currentTarget.style.background = T.bgHover; }}
                      onMouseLeave={(e) => { if (nav !== subj.id) e.currentTarget.style.background = "transparent"; }}
                      style={{ display: "flex", alignItems: "center", gap: 8, flex: 1, padding: "9px 12px 9px 4px", border: "none", cursor: "pointer", background: nav === subj.id ? T.accentLight : "transparent", color: nav === subj.id ? T.accentText : T.text, fontSize: 13, fontWeight: isActiveSubject ? 650 : 500, transition: "all 0.15s", borderRadius: 0, boxShadow: nav === subj.id ? `inset 3px 0 0 ${T.accent}` : "none" }}>
                      {isExpanded
                        ? <FolderOpen size={16} weight="duotone" color={theme.accent} />
                        : <Folder size={16} weight="duotone" color={theme.accent} />
                      }
                      <span style={{ flex: 1, textAlign: "left" }}>{subj.name}</span>
                      <span style={{ fontSize: 10, color: theme.text, background: theme.bg, padding: "2px 7px", borderRadius: 10, fontWeight: 700 }}>{subjCount}</span>
                    </button>
                  </div>

                  {/* Topic sub-folders (expandable) */}
                  {isExpanded && (
                    <div style={{ background: T.bgMuted }}>
                      {topics.map((topic) => {
                        const isActiveTopic = typeof nav === "object" && nav?.subject === subj.id && nav?.topic === topic;
                        const topicCount = countByTopic(subj.id, topic);
                        return (
                          <button key={topic} onClick={() => setNav({ subject: subj.id, topic })}
                            onMouseEnter={(e) => { if (!isActiveTopic) e.currentTarget.style.background = T.bgHover; }}
                            onMouseLeave={(e) => { if (!isActiveTopic) e.currentTarget.style.background = "transparent"; }}
                            style={{ display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "8px 12px 8px 44px", border: "none", cursor: "pointer", background: isActiveTopic ? T.accentLight : "transparent", color: isActiveTopic ? T.accentText : T.textSec, fontSize: 12, fontWeight: isActiveTopic ? 650 : 500, transition: "all 0.15s", boxShadow: isActiveTopic ? `inset 3px 0 0 ${T.accent}` : "none" }}>
                            <Hash size={13} weight="bold" color={isActiveTopic ? T.accent : T.textTer} />
                            <span style={{ flex: 1, textAlign: "left" }}>{topic}</span>
                            {topicCount > 0 && <span style={{ fontSize: 10, color: T.textTer, fontWeight: 600 }}>{topicCount}</span>}
                          </button>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </Card>
        </div>

        {/* Main content area */}
        <div style={{ flex: 1, minWidth: 0 }}>
          {/* Search bar */}
          <div style={{ display: "flex", gap: 10, marginBottom: 18 }}>
            <div style={{ position: "relative", flex: 1 }}>
              <MagnifyingGlass size={16} weight="bold" color={T.textTer} style={{ position: "absolute", left: 12, top: 11 }} />
              <Input value={search} onChange={setSearch} placeholder={nav ? `Search in ${typeof nav === "string" ? getSubject(nav)?.name : nav.topic}...` : "Search all resources..."} style={{ paddingLeft: 36 }} />
            </div>
            {search && <Btn variant="ghost" onClick={() => setSearch("")}><X size={14} weight="bold" /> Clear</Btn>}
          </div>

          {/* Subject folder cards (shown when nav is null and no search) */}
          {nav === null && !search && (
            <div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: 14, marginBottom: 24 }}>
                {SUBJECTS.map((subj) => {
                  const theme = getSubjectTheme(subj.id);
                  const subjResources = state.resources.filter((r) => r.subject === subj.id);
                  const topics = TOPICS[subj.id] || [];
                  const pdfCount = subjResources.filter((r) => r.type === "pdf").length;
                  const videoCount = subjResources.filter((r) => r.type === "video").length;
                  const docxCount = subjResources.filter((r) => r.type === "docx").length;
                  return (
                    <Card key={subj.id} onClick={() => { setNav(subj.id); if (!expandedSubjects[subj.id]) toggleSubject(subj.id); }} elevated>
                      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
                        <div style={{ width: 44, height: 44, borderRadius: T.r2, background: theme.bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
                          <FolderOpen size={22} weight="duotone" color={theme.accent} />
                        </div>
                        <div>
                          <div style={{ fontSize: 15, fontWeight: 700, color: T.text }}>{subj.name}</div>
                          <div style={{ fontSize: 12, color: T.textTer, marginTop: 2 }}>{topics.length} topics · {subjResources.length} resources</div>
                        </div>
                      </div>
                      {/* File type breakdown */}
                      <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
                        {pdfCount > 0 && <Badge color="#DC2626" bg={T.dangerBg} style={{ fontSize: 10 }}><FilePdf size={12} weight="bold" /> {pdfCount} PDF</Badge>}
                        {videoCount > 0 && <Badge color="#2563EB" bg="#DBEAFE" style={{ fontSize: 10 }}><FileVideo size={12} weight="bold" /> {videoCount} Video</Badge>}
                        {docxCount > 0 && <Badge color={T.accentText} bg={T.accentLight} style={{ fontSize: 10 }}><FileDoc size={12} weight="bold" /> {docxCount} DOCX</Badge>}
                      </div>
                      {/* Topic preview */}
                      <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
                        {topics.slice(0, 4).map((t) => (
                          <span key={t} style={{ fontSize: 10, color: T.textSec, background: T.bgMuted, padding: "3px 8px", borderRadius: 8, fontWeight: 500 }}>{t}</span>
                        ))}
                        {topics.length > 4 && <span style={{ fontSize: 10, color: T.textTer, padding: "3px 4px" }}>+{topics.length - 4} more</span>}
                      </div>
                    </Card>
                  );
                })}
              </div>
            </div>
          )}

          {/* Topic section cards (shown when a subject is selected, no specific topic, no search) */}
          {nav && typeof nav === "string" && !search && (
            <div>
              {(TOPICS[nav] || []).map((topic) => {
                const topicResources = state.resources.filter((r) => r.subject === nav && r.topic === topic);
                const theme = getSubjectTheme(nav);
                if (topicResources.length === 0) return (
                  <div key={topic} style={{ marginBottom: 20 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10, padding: "8px 0" }}>
                      <Hash size={15} weight="bold" color={T.textTer} />
                      <span style={{ fontSize: 14, fontWeight: 700, color: T.text }}>{topic}</span>
                      <span style={{ fontSize: 11, color: T.textTer, marginLeft: 4 }}>0 resources</span>
                    </div>
                    <div style={{ padding: "20px 0", textAlign: "center", color: T.textTer, fontSize: 13, background: T.bgMuted, borderRadius: T.r2, border: `1px dashed ${T.border}` }}>No resources yet</div>
                  </div>
                );
                return (
                  <div key={topic} style={{ marginBottom: 24 }}>
                    {/* Topic header */}
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12, padding: "4px 0" }}>
                      <button onClick={() => setNav({ subject: nav, topic })}
                        onMouseEnter={(e) => e.currentTarget.style.color = T.accent}
                        onMouseLeave={(e) => e.currentTarget.style.color = T.text}
                        style={{ display: "flex", alignItems: "center", gap: 8, background: "none", border: "none", cursor: "pointer", padding: 0, color: T.text, transition: "color 0.15s" }}>
                        <div style={{ width: 28, height: 28, borderRadius: T.r1, background: theme.bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
                          <Hash size={14} weight="bold" color={theme.accent} />
                        </div>
                        <span style={{ fontSize: 15, fontWeight: 700 }}>{topic}</span>
                        <span style={{ fontSize: 12, color: T.textTer, fontWeight: 500 }}>{topicResources.length} resource{topicResources.length !== 1 ? "s" : ""}</span>
                        <CaretRight size={14} weight="bold" color={T.textTer} />
                      </button>
                    </div>
                    {/* Resources row */}
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: 12 }}>
                      {topicResources.map((r) => (
                        <Card key={r.id} onClick={() => setViewingResource(r)} elevated style={{ padding: 16 }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                            <div style={{ width: 36, height: 36, borderRadius: T.r1, background: r.type === "pdf" ? T.dangerBg : r.type === "video" ? "#DBEAFE" : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                              <FileIcon type={r.type} size={16} />
                            </div>
                            <div style={{ flex: 1, minWidth: 0 }}>
                              <div style={{ fontSize: 13, fontWeight: 600, color: T.text, lineHeight: 1.4, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{r.title}</div>
                              <div style={{ display: "flex", gap: 6, alignItems: "center", marginTop: 4 }}>
                                <Badge color={T.textSec} bg={T.bgMuted} style={{ fontSize: 9 }}>{r.type.toUpperCase()}</Badge>
                                <span style={{ fontSize: 11, color: T.textTer }}>{formatDate(r.date)}</span>
                              </div>
                            </div>
                            <button onClick={(e) => { e.stopPropagation(); dispatch({ type: "TOGGLE_BOOKMARK", payload: r.id }); }} style={{ background: "none", border: "none", cursor: "pointer", padding: 4, flexShrink: 0 }}>
                              <BookmarkSimple size={16} weight={isBookmarked(r.id) ? "fill" : "regular"} color={isBookmarked(r.id) ? T.accent : T.textTer} />
                            </button>
                          </div>
                        </Card>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Individual topic view or search results — show resource cards */}
          {((nav && typeof nav === "object") || search) && (
            <div>
              {filtered.length === 0 ? <EmptyState icon={Books} message="No resources found" /> : (
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 14 }}>
                  {filtered.map((r) => (
                    <Card key={r.id} onClick={() => setViewingResource(r)} elevated>
                      <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
                        <div style={{ width: 42, height: 42, borderRadius: T.r2, background: r.type === "pdf" ? T.dangerBg : r.type === "video" ? "#DBEAFE" : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                          <FileIcon type={r.type} />
                        </div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: 13, fontWeight: 650, color: T.text, marginBottom: 8, lineHeight: 1.4 }}>{r.title}</div>
                          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center" }}>
                            <SubjectBadge subjectId={r.subject} small />
                            <Badge color={T.textSec} bg={T.bgMuted} style={{ fontSize: 10 }}>{r.type.toUpperCase()}</Badge>
                          </div>
                          <div style={{ fontSize: 11, color: T.textTer, marginTop: 8 }}>{formatDate(r.date)}</div>
                        </div>
                      </div>
                    </Card>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* All resources flat view when at root with search */}
          {nav === null && search && (
            <div>
              {filtered.length === 0 ? <EmptyState icon={Books} message="No resources found" /> : (
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 14 }}>
                  {filtered.map((r) => (
                    <Card key={r.id} onClick={() => setViewingResource(r)} elevated>
                      <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
                        <div style={{ width: 42, height: 42, borderRadius: T.r2, background: r.type === "pdf" ? T.dangerBg : r.type === "video" ? "#DBEAFE" : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                          <FileIcon type={r.type} />
                        </div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ fontSize: 13, fontWeight: 650, color: T.text, marginBottom: 8, lineHeight: 1.4 }}>{r.title}</div>
                          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center" }}>
                            <SubjectBadge subjectId={r.subject} small />
                            <Badge color={T.textSec} bg={T.bgMuted} style={{ fontSize: 10 }}>{r.type.toUpperCase()}</Badge>
                          </div>
                          <div style={{ fontSize: 11, color: T.textTer, marginTop: 8 }}>{formatDate(r.date)}</div>
                        </div>
                      </div>
                    </Card>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function VideoLessons({ state, dispatch }) {
  const [sel, setSel] = useState(null);
  const [aCh, setACh] = useState(null);

  if (sel) {
    const lesson = state.videoLessons.find((l) => l.id === sel);
    if (!lesson) return null;
    const cc = lesson.chapters.filter((c) => c.completed).length;
    const embedUrl = lesson.videoUrl;
    const isYT = embedUrl && embedUrl.includes("youtube.com/embed");
    return (
      <div>
        <BackBtn onClick={() => { setSel(null); setACh(null); }} />
        <div style={{ display: "grid", gridTemplateColumns: "1fr 320px", gap: 20 }}>
          <div>
            <div style={{ borderRadius: T.r3, aspectRatio: "16/9", marginBottom: 18, overflow: "hidden", background: "#000", border: `1px solid ${T.border}` }}>
              {isYT ? <iframe src={embedUrl + "?rel=0"} style={{ width: "100%", height: "100%", border: "none" }} allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen title={lesson.title} /> : (
                <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", background: T.bgMuted }}><Play size={48} weight="fill" color={T.textTer} /></div>
              )}
            </div>
            <h2 style={{ fontSize: 22, fontWeight: 800, color: T.text, margin: "0 0 10px", letterSpacing: -0.4 }}>{lesson.title}</h2>
            <SubjectBadge subjectId={lesson.subject} />
            <p style={{ fontSize: 14, color: T.textSec, lineHeight: 1.7, marginTop: 12 }}>{lesson.description}</p>
          </div>
          <Card elevated style={{ padding: 0, height: "fit-content" }}>
            <div style={{ padding: "16px 18px", borderBottom: `1px solid ${T.border}` }}>
              <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: 0 }}>Chapters</h3>
              <div style={{ fontSize: 12, color: T.textTer, marginTop: 4 }}>{cc}/{lesson.chapters.length} completed</div>
              <div style={{ marginTop: 8 }}><Progress value={(cc / lesson.chapters.length) * 100} /></div>
            </div>
            {lesson.chapters.map((ch) => (
              <div key={ch.id} onClick={() => setACh(ch.id)} style={{ padding: "12px 18px", display: "flex", alignItems: "center", gap: 10, cursor: "pointer", background: (aCh || lesson.chapters[0]?.id) === ch.id ? T.accentLight : "transparent", borderLeft: (aCh || lesson.chapters[0].id) === ch.id ? `3px solid ${T.accent}` : "3px solid transparent", transition: "all 0.15s" }}>
                <button onClick={(e) => { e.stopPropagation(); dispatch({ type: "TOGGLE_CHAPTER_COMPLETE", payload: { lessonId: lesson.id, chapterId: ch.id } }); }}
                  style={{ width: 22, height: 22, borderRadius: "50%", border: ch.completed ? "none" : `2px solid ${T.border}`, background: ch.completed ? T.success : "transparent", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", flexShrink: 0 }}>
                  {ch.completed && <CheckCircle size={14} weight="fill" color="#fff" />}
                </button>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 13, fontWeight: 550, color: T.text }}>{ch.title}</div>
                  <div style={{ fontSize: 11, color: T.textTer }}>{ch.duration}</div>
                </div>
              </div>
            ))}
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader title="Video Lessons" subtitle="Watch and learn at your own pace" />
      {state.videoLessons.length === 0 && (
        <div style={{ textAlign: "center", padding: "48px 20px" }}>
          <EmptyStateIllustration type="default" size={100} />
          <div style={{ fontSize: 16, fontWeight: 700, color: T.text, marginTop: 12, fontFamily: "'Bricolage Grotesque', sans-serif" }}>No video lessons yet</div>
          <div style={{ fontSize: 13, color: T.textTer, marginTop: 4 }}>Video lessons will appear here once they're added.</div>
        </div>
      )}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 16 }}>
        {state.videoLessons.map((lesson) => {
          const cc = lesson.chapters.filter((c) => c.completed).length;
          const pct = Math.round((cc / lesson.chapters.length) * 100);
          const theme = getSubjectTheme(lesson.subject);
          return (
            <Card key={lesson.id} onClick={() => setSel(lesson.id)} elevated>
              <div style={{ background: `linear-gradient(135deg, ${theme.bg}, ${T.bgMuted})`, borderRadius: T.r2, aspectRatio: "16/9", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 14, position: "relative", overflow: "hidden" }}>
                <div style={{ position: "absolute", inset: 0, background: `radial-gradient(circle at center, ${theme.accent}18 0%, transparent 70%)` }} />
                <div style={{ width: 52, height: 52, borderRadius: "50%", background: "rgba(255,255,255,0.85)", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 4px 16px rgba(0,0,0,0.1)", zIndex: 1 }}>
                  <Play size={22} weight="fill" color={theme.accent} />
                </div>
              </div>
              <h3 style={{ fontSize: 15, fontWeight: 650, color: T.text, margin: "0 0 8px" }}>{lesson.title}</h3>
              <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 12 }}>
                <SubjectBadge subjectId={lesson.subject} small />
                <span style={{ fontSize: 12, color: T.textTer }}>{lesson.chapters.length} chapters</span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: T.textSec, marginBottom: 6 }}>
                <span>{cc}/{lesson.chapters.length} completed</span><span style={{ color: T.accent, fontWeight: 700 }}>{pct}%</span>
              </div>
              <Progress value={pct} />
            </Card>
          );
        })}
      </div>
    </div>
  );
}

function QuizGenerator({ state, dispatch }) {
  const [view, setView] = useState("list");
  const [selQuiz, setSelQuiz] = useState(null);
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const [timeUp, setTimeUp] = useState(false);
  const [nT, snT] = useState(""); const [nS, snS] = useState(""); const [nTo, snTo] = useState(""); const [nTL, snTL] = useState(15); const [nQ, snQ] = useState([]);
  const [filterSubj, setFilterSubj] = useState("");
  const timer = useTimer(selQuiz?.timeLimit || 15, () => setTimeUp(true));

  function startQuiz(q) { setSelQuiz(q); setAnswers({}); setSubmitted(false); setTimeUp(false); setView("take"); }
  function submitQuiz() { setSubmitted(true); timer.stop(); setView("results"); dispatch({ type: "ADD_TOAST", payload: { message: "Quiz submitted!", variant: "success" } }); triggerCelebration("coins"); }
  function getAutoScore() { if (!selQuiz) return { earned: 0, total: 0 }; let e = 0, t = 0; selQuiz.questions.forEach((q) => { t += q.marks; if (q.type === "mcq" && answers[q.id] === q.correct) e += q.marks; }); return { earned: e, total: t }; }

  if (view === "create") {
    return (
      <div>
        <BackBtn onClick={() => setView("list")} />
        <PageHeader title="Create Quiz" />
        <Card elevated style={{ marginBottom: 20, borderLeft: `3px solid ${T.accent}` }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 14 }}>
            <Input value={nT} onChange={snT} placeholder="Quiz title" />
            <Input value={nTL} onChange={snTL} placeholder="Time limit (min)" type="number" />
            <Select value={nS} onChange={snS} options={SUBJECTS.map((s) => ({ value: s.id, label: s.name }))} placeholder="Select subject" />
            <Select value={nTo} onChange={snTo} options={(TOPICS[nS] || []).map((t) => ({ value: t, label: t }))} placeholder="Select topic" />
          </div>
        </Card>
        {nQ.map((q, idx) => (
          <Card key={idx} elevated style={{ marginBottom: 14 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
              <span style={{ fontSize: 13, fontWeight: 700, color: T.text }}>Question {idx + 1}</span>
              <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                <Select value={q.type} onChange={(v) => { const u = [...nQ]; u[idx] = { ...u[idx], type: v }; snQ(u); }} options={[{ value: "mcq", label: "MCQ" }, { value: "short", label: "Short Answer" }, { value: "structured", label: "Structured" }]} style={{ fontSize: 12 }} />
                <Input value={q.marks} onChange={(v) => { const u = [...nQ]; u[idx] = { ...u[idx], marks: parseInt(v) || 0 }; snQ(u); }} type="number" style={{ width: 60 }} />
                <span style={{ fontSize: 12, color: T.textTer }}>marks</span>
                <button onClick={() => snQ(nQ.filter((_, i) => i !== idx))} style={{ background: "none", border: "none", cursor: "pointer", padding: 4 }}><Trash size={14} weight="bold" color={T.danger} /></button>
              </div>
            </div>
            <Textarea value={q.text} onChange={(v) => { const u = [...nQ]; u[idx] = { ...u[idx], text: v }; snQ(u); }} placeholder="Question text" />
            {q.type === "mcq" && (
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 10 }}>
                {q.options.map((opt, oIdx) => (
                  <div key={oIdx} style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <input type="radio" name={`q${idx}`} checked={q.correct === oIdx} onChange={() => { const u = [...nQ]; u[idx] = { ...u[idx], correct: oIdx }; snQ(u); }} style={{ accentColor: T.accent }} />
                    <Input value={opt} onChange={(v) => { const u = [...nQ]; u[idx].options[oIdx] = v; snQ(u); }} placeholder={`Option ${oIdx + 1}`} />
                  </div>
                ))}
              </div>
            )}
            {q.type !== "mcq" && <Textarea value={q.modelAnswer} onChange={(v) => { const u = [...nQ]; u[idx] = { ...u[idx], modelAnswer: v }; snQ(u); }} placeholder="Model answer" rows={2} style={{ marginTop: 10 }} />}
          </Card>
        ))}
        <div style={{ display: "flex", gap: 10 }}>
          <Btn variant="secondary" onClick={() => snQ([...nQ, { id: nQ.length + 1, type: "mcq", text: "", options: ["", "", "", ""], correct: 0, marks: 2, modelAnswer: "" }])}><Plus size={14} weight="bold" /> Add Question</Btn>
          <Btn onClick={() => { if (!nT || !nS || nQ.length === 0) return; dispatch({ type: "ADD_QUIZ", payload: { title: nT, subject: nS, topic: nTo, timeLimit: parseInt(nTL), questions: nQ.map((q, i) => ({ ...q, id: i + 1 })) } }); dispatch({ type: "ADD_TOAST", payload: { message: `Quiz "${nT}" created`, variant: "success" } }); snT(""); snS(""); snTo(""); snTL(15); snQ([]); setView("list"); }} disabled={!nT || !nS || nQ.length === 0}>Save Quiz</Btn>
        </div>
      </div>
    );
  }

  if (view === "results" && selQuiz) {
    const { earned, total } = getAutoScore();
    const pct = Math.round((earned / total) * 100);
    return (
      <div>
        <BackBtn onClick={() => setView("list")} />
        <PageHeader title="Quiz Results" subtitle={selQuiz.title} />
        <div style={{ display: "grid", gridTemplateColumns: "200px 1fr", gap: 20 }}>
          <Card elevated style={{ textAlign: "center", borderTop: `3px solid ${pct >= 70 ? T.success : pct >= 50 ? T.warning : T.danger}` }}>
            <Trophy size={32} weight="duotone" color={pct >= 70 ? T.success : pct >= 50 ? T.warning : T.danger} style={{ marginBottom: 8 }} />
            <div style={{ fontSize: 44, fontWeight: 800, color: pct >= 70 ? T.success : pct >= 50 ? T.warning : T.danger, letterSpacing: -1 }}>{pct}%</div>
            <div style={{ fontSize: 14, color: T.textSec, marginTop: 4 }}>{earned} / {total} marks</div>
            <div style={{ fontSize: 11, color: T.textTer, marginTop: 10 }}>MCQ auto-graded</div>
          </Card>
          <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            {selQuiz.questions.map((q, idx) => {
              const ok = q.type === "mcq" && answers[q.id] === q.correct;
              const wrong = q.type === "mcq" && answers[q.id] !== undefined && answers[q.id] !== q.correct;
              return (
                <Card key={q.id} elevated style={{ borderLeft: `3px solid ${q.type === "mcq" ? (ok ? T.success : wrong ? T.danger : T.border) : T.accent}` }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                    <span style={{ fontSize: 12, fontWeight: 700, color: T.textTer }}>Q{idx + 1} — {q.type.toUpperCase()} ({q.marks}m)</span>
                    {q.type === "mcq" && <Badge color={ok ? T.success : T.danger} bg={ok ? T.successBg : T.dangerBg}>{ok ? "Correct" : "Incorrect"}</Badge>}
                    {q.type !== "mcq" && <Badge color="#2563EB" bg="#DBEAFE">Needs Review</Badge>}
                  </div>
                  <p style={{ fontSize: 14, color: T.text, margin: "0 0 10px", whiteSpace: "pre-wrap", lineHeight: 1.6 }}>{q.text}</p>
                  {q.type === "mcq" && <div><div style={{ fontSize: 13, color: T.textSec }}>Your answer: <strong style={{ color: T.text }}>{q.options[answers[q.id]] || "No answer"}</strong></div>{wrong && <div style={{ fontSize: 13, color: T.success, marginTop: 4 }}>Correct: <strong>{q.options[q.correct]}</strong></div>}</div>}
                  {q.type !== "mcq" && <div><div style={{ fontSize: 12, fontWeight: 600, color: T.textTer, marginBottom: 4 }}>Your answer:</div><div style={{ fontSize: 13, color: T.text, background: T.bgMuted, padding: 12, borderRadius: T.r2, marginBottom: 8 }}>{answers[q.id] || "No answer"}</div><div style={{ fontSize: 12, fontWeight: 600, color: T.textTer, marginBottom: 4 }}>Model answer:</div><div style={{ fontSize: 13, color: T.text, background: T.successBg, padding: 12, borderRadius: T.r2 }}>{q.modelAnswer}</div></div>}
                </Card>
              );
            })}
          </div>
        </div>
      </div>
    );
  }

  if (view === "take" && selQuiz) {
    return (
      <div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div><BackBtn onClick={() => setView("list")} /><h1 style={{ fontSize: 20, fontWeight: 800, color: T.text, margin: 0 }}>{selQuiz.title}</h1></div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 20, fontWeight: 800, color: timer.seconds < 60 ? T.danger : T.text, background: timer.seconds < 60 ? T.dangerBg : T.bgMuted, padding: "8px 16px", borderRadius: T.r2, fontFamily: "'JetBrains Mono', monospace", border: `1.5px solid ${timer.seconds < 60 ? "#FECACA" : T.border}` }}>
              <Timer size={18} weight="bold" /> {timer.display}
            </div>
            {!timer.running && !submitted && <Btn onClick={timer.start} variant="secondary"><Play size={14} weight="fill" /> Start</Btn>}
            <Btn onClick={submitQuiz}>Submit Quiz</Btn>
          </div>
        </div>
        {timeUp && <div style={{ background: T.dangerBg, border: `1px solid #FECACA`, borderRadius: T.r2, padding: 12, marginBottom: 16, display: "flex", alignItems: "center", gap: 8, color: T.danger, fontSize: 13, fontWeight: 600 }}><Warning size={16} weight="fill" /> Time is up! Please submit your quiz.</div>}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {selQuiz.questions.map((q, idx) => (
            <Card key={q.id} elevated>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12 }}>
                <span style={{ fontSize: 14, fontWeight: 700, color: T.text }}>Question {idx + 1}</span>
                <Badge color={T.textSec} bg={T.bgMuted}>{q.marks}m · {q.type.toUpperCase()}</Badge>
              </div>
              <p style={{ fontSize: 14, color: T.text, margin: "0 0 14px", lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{q.text}</p>
              {q.type === "mcq" ? (
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {q.options.map((opt, oIdx) => (
                    <label key={oIdx} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", borderRadius: T.r2, border: `1.5px solid ${answers[q.id] === oIdx ? T.accent : T.border}`, background: answers[q.id] === oIdx ? T.accentLight : "transparent", cursor: "pointer", fontSize: 14, color: T.text, transition: "all 0.15s" }}>
                      <input type="radio" name={`quiz-${q.id}`} checked={answers[q.id] === oIdx} onChange={() => setAnswers({ ...answers, [q.id]: oIdx })} style={{ accentColor: T.accent }} />
                      {opt}
                    </label>
                  ))}
                </div>
              ) : <Textarea value={answers[q.id] || ""} onChange={(v) => setAnswers({ ...answers, [q.id]: v })} placeholder="Type your answer here..." rows={q.type === "structured" ? 6 : 3} />}
            </Card>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader title="Quizzes" subtitle="Test your knowledge" action={<Btn onClick={() => setView("create")}><Plus size={15} weight="bold" /> Create Quiz</Btn>} />
      <div style={{ display: "flex", gap: 6, marginBottom: 18, flexWrap: "wrap" }}>
        <Btn variant={!filterSubj ? "primary" : "secondary"} size="sm" onClick={() => setFilterSubj("")}>All</Btn>
        {SUBJECTS.map(s => <Btn key={s.id} variant={filterSubj === s.id ? "primary" : "secondary"} size="sm" onClick={() => setFilterSubj(s.id)}>{s.name}</Btn>)}
      </div>
      {state.quizzes.filter(q => !filterSubj || q.subject === filterSubj).length === 0 && (
        <div style={{ textAlign: "center", padding: "48px 20px" }}>
          <EmptyStateIllustration type="default" size={100} />
          <div style={{ fontSize: 16, fontWeight: 700, color: T.text, marginTop: 12, fontFamily: "'Bricolage Grotesque', sans-serif" }}>{state.quizzes.length === 0 ? "No quizzes yet" : "No quizzes for this subject"}</div>
          <div style={{ fontSize: 13, color: T.textTer, marginTop: 4 }}>Create your first quiz with the button above.</div>
        </div>
      )}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 16 }}>
        {state.quizzes.filter(q => !filterSubj || q.subject === filterSubj).map((quiz) => {
          const tm = quiz.questions.reduce((s, q) => s + q.marks, 0);
          const mc = quiz.questions.filter((q) => q.type === "mcq").length;
          const wr = quiz.questions.length - mc;
          const theme = getSubjectTheme(quiz.subject);
          return (
            <Card key={quiz.id} onClick={() => startQuiz(quiz)} elevated>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
                <div style={{ width: 40, height: 40, borderRadius: T.r2, background: T.accentLight, display: "flex", alignItems: "center", justifyContent: "center" }}><Lightning size={20} weight="duotone" color={T.accent} /></div>
                <h3 style={{ fontSize: 14, fontWeight: 650, color: T.text, margin: 0, flex: 1, lineHeight: 1.3 }}>{quiz.title}</h3>
              </div>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 12 }}>
                <SubjectBadge subjectId={quiz.subject} small />
                {quiz.topic && <Badge color={T.textSec} bg={T.bgMuted} style={{ fontSize: 10 }}>{quiz.topic}</Badge>}
              </div>
              <div style={{ display: "flex", gap: 14, fontSize: 12, color: T.textSec, marginBottom: 12 }}>
                <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Clock size={13} weight="bold" /> {quiz.timeLimit}m</span>
                <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Exam size={13} weight="bold" /> {quiz.questions.length} Qs</span>
                <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Star size={13} weight="bold" /> {tm}m</span>
              </div>
              <div style={{ display: "flex", gap: 6 }}>
                {mc > 0 && <Badge color={T.accentText} bg={T.accentLight} style={{ fontSize: 10 }}>{mc} MCQ</Badge>}
                {wr > 0 && <Badge color="#2563EB" bg="#DBEAFE" style={{ fontSize: 10 }}>{wr} Written</Badge>}
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

function MockExams({ state }) {
  const [view, setView] = useState("list");
  const [selExam, setSelExam] = useState(null);
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const [aSec, setASec] = useState(0);
  const timer = useTimer(selExam?.timeLimit || 90, () => { setSubmitted(true); setView("review"); });

  if (view === "review" && selExam) {
    const allQ = selExam.sections.flatMap((s) => s.questions);
    const totalM = allQ.reduce((s, q) => s + q.marks, 0);
    return (
      <div>
        <BackBtn onClick={() => setView("list")} />
        <PageHeader title="Exam Review" subtitle={selExam.title} />
        <div style={{ display: "grid", gridTemplateColumns: "220px 1fr", gap: 20 }}>
          <div>
            <Card elevated style={{ textAlign: "center", marginBottom: 14, borderTop: `3px solid ${T.accent}` }}>
              <Trophy size={28} weight="duotone" color={T.accent} style={{ marginBottom: 8 }} />
              <div style={{ fontSize: 14, fontWeight: 700, color: T.text, marginBottom: 4 }}>Total Marks</div>
              <div style={{ fontSize: 34, fontWeight: 800, color: T.accent, letterSpacing: -1 }}>{totalM}</div>
              <div style={{ fontSize: 12, color: T.textTer, marginTop: 4 }}>Manual review needed</div>
            </Card>
            <Card elevated>
              <div style={{ fontSize: 13, fontWeight: 700, color: T.text, marginBottom: 12 }}>Navigation</div>
              {selExam.sections.map((section) => (
                <div key={section.id} style={{ marginBottom: 12 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, color: T.textTer, marginBottom: 6 }}>{section.name}</div>
                  <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
                    {section.questions.map((q) => (
                      <div key={q.id} style={{ width: 28, height: 28, borderRadius: T.r1, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 600, background: answers[q.id] ? T.accent : T.bgMuted, color: answers[q.id] ? "#fff" : T.textTer, border: `1px solid ${answers[q.id] ? T.accent : T.border}` }}>{q.id}</div>
                    ))}
                  </div>
                </div>
              ))}
            </Card>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {selExam.sections.map((section) => (
              <div key={section.id}>
                <h3 style={{ fontSize: 15, fontWeight: 700, color: T.text, marginBottom: 14 }}>{section.name}</h3>
                {section.questions.map((q) => (
                  <Card key={q.id} elevated style={{ marginBottom: 14 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                      <span style={{ fontSize: 13, fontWeight: 700, color: T.text }}>Question {q.id}</span>
                      <Badge color={T.textSec} bg={T.bgMuted}>{q.marks}m</Badge>
                    </div>
                    <p style={{ fontSize: 14, color: T.text, margin: "0 0 12px", lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{q.text}</p>
                    <div style={{ fontSize: 12, fontWeight: 600, color: T.textTer, marginBottom: 4 }}>Your answer:</div>
                    <div style={{ fontSize: 13, color: T.text, background: T.bgMuted, padding: 12, borderRadius: T.r2, marginBottom: 10, minHeight: 36, border: `1px solid ${T.border}` }}>{answers[q.id] || "No answer"}</div>
                    <div style={{ fontSize: 12, fontWeight: 600, color: T.textTer, marginBottom: 4 }}>Model answer:</div>
                    <div style={{ fontSize: 13, color: T.text, background: T.successBg, padding: 12, borderRadius: T.r2 }}>{q.modelAnswer}</div>
                  </Card>
                ))}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (view === "take" && selExam) {
    const section = selExam.sections[aSec];
    return (
      <div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div><div style={{ fontSize: 12, color: T.textTer, marginBottom: 2 }}>{selExam.title}</div><h1 style={{ fontSize: 20, fontWeight: 800, color: T.text, margin: 0 }}>{section.name}</h1></div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 20, fontWeight: 800, color: timer.seconds < 300 ? T.danger : T.text, fontFamily: "'JetBrains Mono', monospace", background: timer.seconds < 300 ? T.dangerBg : T.bgMuted, padding: "8px 16px", borderRadius: T.r2, border: `1.5px solid ${timer.seconds < 300 ? "#FECACA" : T.border}` }}><Timer size={18} weight="bold" /> {timer.display}</div>
            {!timer.running && !submitted && <Btn onClick={timer.start} variant="secondary"><Play size={14} weight="fill" /> Start</Btn>}
            <Btn onClick={() => { setSubmitted(true); timer.stop(); setView("review"); }}>Submit</Btn>
          </div>
        </div>
        <div style={{ display: "flex", gap: 6, marginBottom: 20 }}>
          {selExam.sections.map((s, idx) => (
            <button key={s.id} onClick={() => setASec(idx)} style={{ padding: "9px 18px", borderRadius: T.r2, border: `1.5px solid ${idx === aSec ? T.accent : T.border}`, background: idx === aSec ? T.accentLight : "transparent", color: idx === aSec ? T.accentText : T.text, fontSize: 13, fontWeight: 600, cursor: "pointer", transition: "all 0.15s" }}>{s.name}</button>
          ))}
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
          {section.questions.map((q) => (
            <Card key={q.id} elevated>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12 }}>
                <span style={{ fontSize: 14, fontWeight: 700, color: T.text }}>Question {q.id}</span>
                <Badge color={T.textSec} bg={T.bgMuted}>{q.marks}m</Badge>
              </div>
              <p style={{ fontSize: 14, color: T.text, margin: "0 0 14px", lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{q.text}</p>
              <Textarea value={answers[q.id] || ""} onChange={(v) => setAnswers({ ...answers, [q.id]: v })} placeholder="Write your answer here..." rows={Math.max(6, Math.ceil(q.marks / 3))} />
            </Card>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader title="Mock Examinations" subtitle="Practice under exam conditions" />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", gap: 16 }}>
        {state.exams.map((exam) => {
          const totalM = exam.sections.flatMap((s) => s.questions).reduce((sum, q) => sum + q.marks, 0);
          const totalQ = exam.sections.flatMap((s) => s.questions).length;
          return (
            <Card key={exam.id} onClick={() => { setSelExam(exam); setAnswers({}); setSubmitted(false); setASec(0); setView("take"); }} elevated>
              <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
                <div style={{ width: 48, height: 48, borderRadius: T.r3, background: T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <GraduationCap size={24} weight="duotone" color={T.accent} />
                </div>
                <div style={{ flex: 1 }}>
                  <h3 style={{ fontSize: 15, fontWeight: 700, color: T.text, margin: "0 0 8px" }}>{exam.title}</h3>
                  <SubjectBadge subjectId={exam.subject} small />
                  <div style={{ display: "flex", gap: 14, marginTop: 12, fontSize: 12, color: T.textSec }}>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Clock size={13} weight="bold" /> {exam.timeLimit}m</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Exam size={13} weight="bold" /> {totalQ} Qs</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Star size={13} weight="bold" /> {totalM}m</span>
                  </div>
                  <div style={{ display: "flex", gap: 6, marginTop: 10 }}>
                    {exam.sections.map((s) => <Badge key={s.id} color={T.accentText} bg={T.accentLight} style={{ fontSize: 10 }}>{s.name}</Badge>)}
                  </div>
                </div>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

function ProgressTracker({ state, dispatch }) {
  const [sel, setSel] = useState(null);
  const [showNewReport, setShowNewReport] = useState(false);
  const [reportMonth, setReportMonth] = useState("");
  const [reportContent, setReportContent] = useState("");
  const [editingReport, setEditingReport] = useState(null);
  const [viewingReport, setViewingReport] = useState(null);
  const [shareMsg, setShareMsg] = useState("");

  // Generate parent report text for sharing
  function generateParentReport(student) {
    const xp = calcStudentXP(student, state);
    const level = getLevel(xp);
    const gradedSubs = state.submissions.filter(s => s.studentId === student.id && s.status === "graded");
    const avgGrade = gradedSubs.length > 0 ? gradedSubs.map(s => s.grade).join(", ") : "No grades yet";
    const attendanceCount = Object.values(state.attendance).reduce((acc, rec) => acc + (rec[student.id] === "present" || rec[student.id] === "late" ? 1 : 0), 0);
    const totalSessions = Object.keys(state.attendance).length;
    return `📊 A Worthy Progress Report\n👤 Student: ${student.name}\n🎖️ Level: ${level.name} (${xp} XP)\n📋 Grades: ${avgGrade}\n📅 Attendance: ${attendanceCount}/${totalSessions} sessions\n🔥 Study Streak: ${state.wallet.streak} days\n🪙 Coins earned: ${state.wallet.coins}\n\nGenerated by A Worthy LMS · lms.a-worthy.com`;
  }

  function shareReport(student) {
    const text = generateParentReport(student);
    if (navigator.share) {
      navigator.share({ title: `${student.name} — Progress Report`, text });
    } else {
      navigator.clipboard.writeText(text);
      setShareMsg("Report copied to clipboard!");
      setTimeout(() => setShareMsg(""), 2000);
    }
  }

  if (sel) {
    const student = state.students.find((s) => s.id === sel);
    if (!student) return null;
    const scoreData = student.quizResults.map((r) => ({ date: formatDate(r.date), score: Math.round((r.score / r.total) * 100) }));
    const subjScores = {};
    student.quizResults.forEach((r) => { const q = state.quizzes.find((q) => q.id === r.quizId); if (q) { if (!subjScores[q.subject]) subjScores[q.subject] = []; subjScores[q.subject].push(Math.round((r.score / r.total) * 100)); } });
    const barData = Object.entries(subjScores).map(([s, scores]) => ({ name: getSubject(s)?.name || s, value: Math.round(scores.reduce((a, b) => a + b, 0) / scores.length), color: getSubjectTheme(s).accent }));

    return (
      <div>
        <BackBtn onClick={() => setSel(null)} />
        <Card elevated style={{ padding: "24px 32px", marginBottom: 20, borderTop: `3px solid ${T.accent}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 20 }}>
            {(() => { const xp = calcStudentXP(student, state); const lv = getLevel(xp); return (
              <StudentAvatar student={student} size={52} radius={T.r3} />
            ); })()}
            <div style={{ flex: 1 }}>
              <h1 style={{ color: T.text, fontSize: 22, fontWeight: 800, margin: "0 0 4px", letterSpacing: -0.3 }}>{student.name}</h1>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>{student.subjects.map((s) => <SubjectBadge key={s} subjectId={s} small />)}</div>
            </div>
          </div>
          {/* XP / Level */}
          <div style={{ marginBottom: 16 }}>
            <XPBar xp={calcStudentXP(student, state)} />
          </div>
          {/* Badges */}
          {(() => {
            const badges = getStudentBadges(student, state);
            if (badges.length === 0) return null;
            return (
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: T.textSec, marginBottom: 8, letterSpacing: 0.5, textTransform: "uppercase" }}>Achievements</div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                  {BADGE_DEFS.map(b => <BadgeChip key={b.id} badge={b} earned={badges.some(sb => sb.id === b.id)} size="sm" />)}
                </div>
              </div>
            );
          })()}
          {/* Avatar Picker */}
          <div>
            <div style={{ fontSize: 12, fontWeight: 700, color: T.textSec, marginBottom: 10, letterSpacing: 0.5, textTransform: "uppercase" }}>Choose Avatar</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(48px, 1fr))", gap: 8 }}>
              {AVATAR_OPTIONS.map(av => {
                const selected = student.avatar === av.id;
                return (
                  <button key={av.id} title={av.id} onClick={() => dispatch({ type: "UPDATE_STUDENT_AVATAR", payload: { studentId: student.id, avatar: av.id } })} style={{ width: "100%", aspectRatio: "1", borderRadius: T.r2, border: `2.5px solid ${selected ? av.ring : T.border}`, background: selected ? av.bg : T.bgMuted, cursor: "pointer", fontSize: 20, display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.15s", boxShadow: selected ? `0 0 0 3px ${av.ring}33` : "none", transform: selected ? "scale(1.1)" : "scale(1)" }}>
                    {av.emoji}
                  </button>
                );
              })}
            </div>
          </div>
        </Card>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginBottom: 20 }}>
          <Card elevated>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Score Trend</h3>
            <ResponsiveContainer width="100%" height={200}>
              <LineChart data={scoreData}><CartesianGrid strokeDasharray="3 3" stroke={T.border} /><XAxis dataKey="date" tick={{ fontSize: 11, fill: T.textTer }} /><YAxis domain={[0, 100]} tick={{ fontSize: 11, fill: T.textTer }} /><Tooltip contentStyle={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: T.r2, color: T.text, fontSize: 12, boxShadow: T.shadow2 }} /><Line type="monotone" dataKey="score" stroke={T.accent} strokeWidth={2.5} dot={{ fill: T.accent, r: 4, strokeWidth: 2, stroke: T.bgCard }} activeDot={{ r: 6, fill: T.accent }} /></LineChart>
            </ResponsiveContainer>
          </Card>
          <Card elevated>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Average by Subject</h3>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={barData}><CartesianGrid strokeDasharray="3 3" stroke={T.border} /><XAxis dataKey="name" tick={{ fontSize: 10, fill: T.textTer }} /><YAxis domain={[0, 100]} tick={{ fontSize: 11, fill: T.textTer }} /><Tooltip contentStyle={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: T.r2, color: T.text, fontSize: 12, boxShadow: T.shadow2 }} /><Bar dataKey="value" radius={[6, 6, 0, 0]}>{barData.map((e, i) => <Cell key={i} fill={e.color} />)}</Bar></BarChart>
            </ResponsiveContainer>
          </Card>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
          <Card elevated>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Topic Completion</h3>
            {Object.entries(student.topicCompletion).map(([subj, topics]) => {
              const theme = getSubjectTheme(subj);
              return (
                <div key={subj} style={{ marginBottom: 18 }}>
                  <SubjectBadge subjectId={subj} small />
                  <div style={{ marginTop: 8, display: "flex", flexDirection: "column", gap: 8 }}>
                    {Object.entries(topics).map(([topic, pct]) => (
                      <div key={topic}><div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: T.textSec, marginBottom: 4 }}><span>{topic}</span><span style={{ color: theme.accent, fontWeight: 700 }}>{pct}%</span></div><Progress value={pct} color={theme.accent} bg={theme.bg} /></div>
                    ))}
                  </div>
                </div>
              );
            })}
          </Card>
          <Card elevated>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Quiz History</h3>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {student.quizResults.map((r, idx) => {
                const quiz = state.quizzes.find((q) => q.id === r.quizId);
                const pct = Math.round((r.score / r.total) * 100);
                return (
                  <div key={idx} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 12px", background: T.bgMuted, borderRadius: T.r2, border: `1px solid ${T.border}` }}>
                    <div><div style={{ fontSize: 13, fontWeight: 550, color: T.text }}>{quiz?.title || "Quiz"}</div><div style={{ fontSize: 11, color: T.textTer }}>{formatDate(r.date)}</div></div>
                    <div style={{ textAlign: "right" }}><div style={{ fontSize: 16, fontWeight: 800, color: pct >= 70 ? T.success : pct >= 50 ? T.warning : T.danger }}>{pct}%</div><div style={{ fontSize: 11, color: T.textTer }}>{r.score}/{r.total}</div></div>
                  </div>
                );
              })}
            </div>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "20px 0 14px" }}>Materials Accessed</h3>
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {student.materialsAccessed.map((rId) => {
                const resource = state.resources.find((r) => r.id === rId);
                if (!resource) return null;
                return <div key={rId} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", fontSize: 13, color: T.text }}><div style={{ width: 26, height: 26, borderRadius: T.r1, background: resource.type === "pdf" ? T.dangerBg : resource.type === "video" ? "#DBEAFE" : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center" }}><FileIcon type={resource.type} size={13} /></div>{resource.title}</div>;
              })}
            </div>
          </Card>
        </div>

        {/* ━━━ MONTHLY PROGRESS REPORTS ━━━ */}
        <div style={{ marginTop: 24 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, color: T.text, margin: 0, letterSpacing: -0.3 }}>Monthly Progress Reports</h2>
            <Btn onClick={() => { setShowNewReport(!showNewReport); setEditingReport(null); setViewingReport(null); }}><PencilSimpleLine size={15} weight="bold" /> Write Report</Btn>
          </div>

          {/* New / Edit report form */}
          {(showNewReport || editingReport) && (
            <Card elevated style={{ marginBottom: 20, borderLeft: `3px solid ${T.accent}` }}>
              <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>
                {editingReport ? `Edit Report — ${editingReport.title}` : `New Report for ${student.name}`}
              </h3>
              {!editingReport && (
                <div style={{ marginBottom: 14 }}>
                  <Input value={reportMonth} onChange={setReportMonth} type="month" style={{ maxWidth: 220 }} />
                </div>
              )}
              <Textarea
                value={editingReport ? editingReport.content : reportContent}
                onChange={(v) => editingReport ? setEditingReport({ ...editingReport, content: v }) : setReportContent(v)}
                placeholder={`Write a progress report for ${student.name} (~300 words). Cover overall progress, subject-specific performance, strengths, areas for improvement, and recommendations for parents...`}
                rows={14}
              />
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 14 }}>
                <div style={{ fontSize: 12, color: T.textTer }}>
                  {(editingReport ? editingReport.content : reportContent).split(/\s+/).filter(Boolean).length} words
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <Btn variant="secondary" onClick={() => { setShowNewReport(false); setEditingReport(null); setReportContent(""); setReportMonth(""); }}><X size={14} weight="bold" /> Cancel</Btn>
                  {editingReport ? (
                    <Btn onClick={() => {
                      dispatch({ type: "UPDATE_REPORT", payload: { id: editingReport.id, content: editingReport.content } });
                      dispatch({ type: "ADD_TOAST", payload: { message: "Report updated", variant: "success" } });
                      setEditingReport(null);
                    }}><CheckCircle size={14} weight="bold" /> Save Changes</Btn>
                  ) : (
                    <Btn onClick={() => {
                      if (!reportMonth || !reportContent.trim()) return;
                      const monthLabel = new Date(reportMonth + "-01").toLocaleDateString("en-GB", { month: "long", year: "numeric" });
                      dispatch({ type: "ADD_REPORT", payload: { studentId: student.id, month: reportMonth, title: monthLabel, content: reportContent } });
                      dispatch({ type: "ADD_TOAST", payload: { message: `Report for ${monthLabel} created`, variant: "success" } });
                      setReportContent(""); setReportMonth(""); setShowNewReport(false);
                    }} disabled={!reportMonth || !reportContent.trim()}><CheckCircle size={14} weight="bold" /> Save Report</Btn>
                  )}
                </div>
              </div>
            </Card>
          )}

          {/* Viewing a report */}
          {viewingReport && (
            <Card elevated style={{ marginBottom: 20, borderTop: `3px solid ${T.accent}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
                <div>
                  <h3 style={{ fontSize: 16, fontWeight: 700, color: T.text, margin: "0 0 6px" }}>{viewingReport.title}</h3>
                  <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <span style={{ fontSize: 12, color: T.textTer }}>Written {formatDate(viewingReport.createdAt)}</span>
                    {viewingReport.sharedWithParents
                      ? <Badge color={T.success} bg={T.successBg}><CheckCircle size={11} weight="fill" /> Shared with Parents</Badge>
                      : <Badge color={T.textSec} bg={T.bgMuted}>Draft</Badge>
                    }
                  </div>
                </div>
                <div style={{ display: "flex", gap: 6 }}>
                  <Btn size="sm" variant="secondary" onClick={() => { setEditingReport({ ...viewingReport }); setViewingReport(null); setShowNewReport(false); }}><PencilSimpleLine size={13} weight="bold" /> Edit</Btn>
                  {!viewingReport.sharedWithParents ? (
                    <Btn size="sm" onClick={() => {
                      dispatch({ type: "SHARE_REPORT", payload: viewingReport.id });
                      dispatch({ type: "ADD_TOAST", payload: { message: "Report shared with parents", variant: "success" } });
                      setViewingReport({ ...viewingReport, sharedWithParents: true });
                    }}><ArrowSquareOut size={13} weight="bold" /> Share with Parents</Btn>
                  ) : (
                    <Btn size="sm" variant="danger" onClick={() => {
                      dispatch({ type: "UNSHARE_REPORT", payload: viewingReport.id });
                      dispatch({ type: "ADD_TOAST", payload: { message: "Report unshared", variant: "info" } });
                      setViewingReport({ ...viewingReport, sharedWithParents: false });
                    }}><X size={13} weight="bold" /> Unshare</Btn>
                  )}
                  <Btn size="sm" variant="ghost" onClick={() => setViewingReport(null)}><X size={13} weight="bold" /></Btn>
                </div>
              </div>
              <div style={{ fontSize: 14, color: T.text, lineHeight: 1.8, whiteSpace: "pre-wrap", background: T.bgMuted, padding: "20px 24px", borderRadius: T.r2, border: `1px solid ${T.border}` }}>
                {viewingReport.content}
              </div>
              <div style={{ marginTop: 12, fontSize: 12, color: T.textTer, textAlign: "right" }}>
                {viewingReport.content.split(/\s+/).filter(Boolean).length} words
              </div>
            </Card>
          )}

          {/* Report list */}
          {!viewingReport && !editingReport && (() => {
            const studentReports = state.reports.filter(r => r.studentId === student.id).sort((a, b) => b.month.localeCompare(a.month));
            if (studentReports.length === 0) return (
              <Card elevated style={{ textAlign: "center", padding: 40 }}>
                <div style={{ width: 56, height: 56, borderRadius: T.r3, background: T.accentLight, display: "inline-flex", alignItems: "center", justifyContent: "center", marginBottom: 14 }}>
                  <Notebook size={24} weight="duotone" color={T.accent} />
                </div>
                <p style={{ fontSize: 14, color: T.textSec, fontWeight: 500, margin: "0 0 12px" }}>No progress reports yet</p>
                <Btn onClick={() => setShowNewReport(true)}><PencilSimpleLine size={14} weight="bold" /> Write First Report</Btn>
              </Card>
            );
            return (
              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                {studentReports.map(report => (
                  <Card key={report.id} onClick={() => { setViewingReport(report); setShowNewReport(false); setEditingReport(null); }} elevated style={{ padding: 18, borderLeft: `3px solid ${report.sharedWithParents ? T.success : T.accent}` }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
                      <div style={{ width: 44, height: 44, borderRadius: T.r2, background: report.sharedWithParents ? T.successBg : T.accentLight, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                        <Notebook size={20} weight="duotone" color={report.sharedWithParents ? T.success : T.accent} />
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 14, fontWeight: 650, color: T.text }}>{report.title}</div>
                        <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4 }}>
                          <span style={{ fontSize: 12, color: T.textTer }}>Written {formatDate(report.createdAt)}</span>
                          {report.sharedWithParents
                            ? <Badge color={T.success} bg={T.successBg} style={{ fontSize: 10 }}><CheckCircle size={11} weight="fill" /> Shared</Badge>
                            : <Badge color={T.textSec} bg={T.bgMuted} style={{ fontSize: 10 }}>Draft</Badge>
                          }
                        </div>
                      </div>
                      <div style={{ fontSize: 12, color: T.textTer, textAlign: "right", flexShrink: 0 }}>
                        {report.content.split(/\s+/).filter(Boolean).length} words
                      </div>
                      <CaretRight size={16} weight="bold" color={T.textTer} />
                    </div>
                  </Card>
                ))}
              </div>
            );
          })()}
        </div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader title="Student Progress" subtitle="Track performance and completion" />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", gap: 16 }}>
        {state.students.map((student) => {
          const avg = student.quizResults.length > 0 ? Math.round(student.quizResults.reduce((sum, r) => sum + (r.score / r.total) * 100, 0) / student.quizResults.length) : 0;
          const xp = calcStudentXP(student, state);
          const lv = getLevel(xp);
          const badges = getStudentBadges(student, state);
          return (
            <Card key={student.id} onClick={() => setSel(student.id)} elevated>
              <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 14 }}>
                <StudentAvatar student={student} size={48} radius={T.r3} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 15, fontWeight: 650, color: T.text }}>{student.name}</div>
                  <div style={{ display: "flex", gap: 4, marginTop: 5, flexWrap: "wrap", alignItems: "center" }}>
                    {student.subjects.map((s) => <SubjectBadge key={s} subjectId={s} small />)}
                    <span style={{ fontSize: 10, fontWeight: 700, color: lv.color, background: lv.bg, padding: "2px 7px", borderRadius: 20, marginLeft: 2 }}>{lv.emoji} {lv.name}</span>
                  </div>
                </div>
              </div>
              {/* XP bar compact */}
              <div style={{ marginBottom: 12 }}>
                <XPBar xp={xp} compact />
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, textAlign: "center", marginBottom: badges.length > 0 ? 12 : 0 }}>
                <div style={{ padding: 10, background: T.accentLight, borderRadius: T.r2 }}><div style={{ fontSize: 20, fontWeight: 800, color: T.accent }}>{student.quizResults.length}</div><div style={{ fontSize: 11, color: T.textTer }}>Quizzes</div></div>
                <div style={{ padding: 10, background: avg >= 70 ? T.successBg : avg >= 50 ? T.warningBg : T.dangerBg, borderRadius: T.r2 }}><div style={{ fontSize: 20, fontWeight: 800, color: avg >= 70 ? T.success : avg >= 50 ? T.warning : T.danger }}>{avg}%</div><div style={{ fontSize: 11, color: T.textTer }}>Avg Score</div></div>
                <div style={{ padding: 10, background: lv.bg, borderRadius: T.r2 }}><div style={{ fontSize: 20, fontWeight: 800, color: lv.color, fontFamily: "'JetBrains Mono', monospace" }}>{xp}</div><div style={{ fontSize: 11, color: T.textTer }}>XP</div></div>
              </div>
              {badges.length > 0 && (
                <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
                  {badges.map(b => <span key={b.id} title={b.name} style={{ fontSize: 16 }}>{b.emoji}</span>)}
                </div>
              )}
            </Card>
          );
        })}
      </div>
    </div>
  );
}

/* ━━━ ATTENDANCE ━━━ */
function Attendance({ state, dispatch }) {
  const [showAdd, setShowAdd] = useState(false);
  const [filterSubj, setFilterSubj] = useState("");
  const [view, setView] = useState("sessions");
  const [expanded, setExpanded] = useState(null);
  const [nDate, setNDate] = useState(""); const [nSubj, setNSubj] = useState(""); const [nTime, setNTime] = useState(""); const [nNotes, setNNotes] = useState("");
  const [editingNotes, setEditingNotes] = useState(null);
  const [showQR, setShowQR] = useState(null); // session ID to show QR for

  const TODAY = "2026-03-18";
  const getStudentsForSubject = (subjectId) => state.students.filter(st => st.subjects.includes(subjectId));

  const sessions = state.sessions
    .filter(s => !filterSubj || s.subject === filterSubj)
    .sort((a, b) => b.date.localeCompare(a.date));

  // Stats
  const totalSessions = state.sessions.length;
  const todaySessions = state.sessions.filter(s => s.date === TODAY).length;
  let totalExpected = 0, totalPresent = 0;
  state.sessions.forEach(s => {
    const stu = getStudentsForSubject(s.subject);
    const rec = state.attendance[s.id] || {};
    totalExpected += stu.length;
    totalPresent += Object.values(rec).filter(v => v === "present" || v === "late").length;
  });
  const attendanceRate = totalExpected > 0 ? Math.round((totalPresent / totalExpected) * 100) : 0;

  function addSession() {
    if (!nDate || !nSubj || !nTime) return;
    dispatch({ type: "ADD_SESSION", payload: { date: nDate, subject: nSubj, time: nTime, notes: nNotes } });
    dispatch({ type: "ADD_TOAST", payload: { message: "Session added successfully", variant: "success" } });
    setNDate(""); setNSubj(""); setNTime(""); setNNotes(""); setShowAdd(false);
  }

  // Student summary view
  if (view === "students") {
    const studentStats = state.students.map(student => {
      let expected = 0, present = 0, late = 0, absent = 0;
      state.sessions.forEach(s => {
        if (student.subjects.includes(s.subject)) {
          expected++;
          const status = (state.attendance[s.id] || {})[student.id];
          if (status === "present") present++;
          else if (status === "late") late++;
          else if (status === "absent") absent++;
        }
      });
      const rate = expected > 0 ? Math.round(((present + late) / expected) * 100) : 0;
      return { ...student, expected, present, late, absent, rate };
    });

    return (
      <div>
        <PageHeader title="Attendance" subtitle="Student attendance overview"
          action={<div style={{ display: "flex", gap: 8 }}>
            <Btn variant="secondary" onClick={() => setView("sessions")}><CalendarCheck size={15} weight="bold" /> Sessions</Btn>
            <Btn onClick={() => setShowAdd(true)}><Plus size={15} weight="bold" /> New Session</Btn>
          </div>} />

        {showAdd && (
          <Card elevated style={{ marginBottom: 20, borderLeft: `3px solid ${T.accent}` }}>
            <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Add New Session</h3>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 14 }}>
              <Input value={nDate} onChange={setNDate} type="date" />
              <Select value={nSubj} onChange={setNSubj} options={SUBJECTS.map(s => ({ value: s.id, label: s.name }))} placeholder="Select subject" />
              <Input value={nTime} onChange={setNTime} placeholder="e.g. 14:00–15:30" />
              <Input value={nNotes} onChange={setNNotes} placeholder="Session notes (optional)" />
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <Btn onClick={addSession}><Plus size={14} weight="bold" /> Add</Btn>
              <Btn variant="secondary" onClick={() => setShowAdd(false)}><X size={14} weight="bold" /> Cancel</Btn>
            </div>
          </Card>
        )}

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", gap: 16 }}>
          {studentStats.map(st => {
            const rateColor = st.rate >= 80 ? T.success : st.rate >= 60 ? T.warning : T.danger;
            return (
              <Card key={st.id} elevated>
                <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 16 }}>
                  <StudentAvatar student={st} size={44} radius={T.r3} />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 15, fontWeight: 650, color: T.text }}>{st.name}</div>
                    <div style={{ display: "flex", gap: 4, marginTop: 4, flexWrap: "wrap" }}>{st.subjects.map(s => <SubjectBadge key={s} subjectId={s} small />)}</div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ fontSize: 28, fontWeight: 800, color: rateColor, letterSpacing: -1 }}>{st.rate}%</div>
                    <div style={{ fontSize: 11, color: T.textTer }}>attendance</div>
                  </div>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(120px, 1fr))", gap: 8, textAlign: "center" }}>
                  <div style={{ padding: 8, background: T.bgMuted, borderRadius: T.r1 }}>
                    <div style={{ fontSize: 18, fontWeight: 800, color: T.text }}>{st.expected}</div>
                    <div style={{ fontSize: 10, color: T.textTer }}>Expected</div>
                  </div>
                  <div style={{ padding: 8, background: T.successBg, borderRadius: T.r1 }}>
                    <div style={{ fontSize: 18, fontWeight: 800, color: T.success }}>{st.present}</div>
                    <div style={{ fontSize: 10, color: T.textTer }}>Present</div>
                  </div>
                  <div style={{ padding: 8, background: T.warningBg, borderRadius: T.r1 }}>
                    <div style={{ fontSize: 18, fontWeight: 800, color: T.warning }}>{st.late}</div>
                    <div style={{ fontSize: 10, color: T.textTer }}>Late</div>
                  </div>
                  <div style={{ padding: 8, background: T.dangerBg, borderRadius: T.r1 }}>
                    <div style={{ fontSize: 18, fontWeight: 800, color: T.danger }}>{st.absent}</div>
                    <div style={{ fontSize: 10, color: T.textTer }}>Absent</div>
                  </div>
                </div>
                <div style={{ marginTop: 12 }}><Progress value={st.rate} color={rateColor} /></div>
              </Card>
            );
          })}
        </div>
      </div>
    );
  }

  // Sessions view (default)
  return (
    <div>
      <PageHeader title="Attendance" subtitle={`${totalSessions} sessions · ${attendanceRate}% overall attendance`}
        action={<div style={{ display: "flex", gap: 8 }}>
          <Btn variant="secondary" onClick={() => setView("students")}><Users size={15} weight="bold" /> By Student</Btn>
          <Btn onClick={() => setShowAdd(!showAdd)}><Plus size={15} weight="bold" /> New Session</Btn>
        </div>} />

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 14, marginBottom: 24 }}>
        <StatCard icon={CalendarCheck} value={totalSessions} label="Total Sessions" color={T.accent} />
        <StatCard icon={CalendarBlank} value={todaySessions} label="Today's Sessions" color="#3F51EC" />
        <StatCard icon={Users} value={attendanceRate + "%"} label="Attendance Rate" color="#00A85A" />
      </div>

      {/* Add session form */}
      {showAdd && (
        <Card elevated style={{ marginBottom: 20, borderLeft: `3px solid ${T.accent}` }}>
          <h3 style={{ fontSize: 14, fontWeight: 700, color: T.text, margin: "0 0 14px" }}>Add New Session</h3>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 14 }}>
            <Input value={nDate} onChange={setNDate} type="date" />
            <Select value={nSubj} onChange={setNSubj} options={SUBJECTS.map(s => ({ value: s.id, label: s.name }))} placeholder="Select subject" />
            <Input value={nTime} onChange={setNTime} placeholder="e.g. 14:00–15:30" />
            <Input value={nNotes} onChange={setNNotes} placeholder="Session notes (optional)" />
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={addSession}><Plus size={14} weight="bold" /> Add</Btn>
            <Btn variant="secondary" onClick={() => setShowAdd(false)}><X size={14} weight="bold" /> Cancel</Btn>
          </div>
        </Card>
      )}

      {/* Subject filter tabs */}
      <div style={{ display: "flex", gap: 6, marginBottom: 18, flexWrap: "wrap" }}>
        <Btn variant={!filterSubj ? "primary" : "secondary"} size="sm" onClick={() => setFilterSubj("")}>All Subjects</Btn>
        {SUBJECTS.map(s => (
          <Btn key={s.id} variant={filterSubj === s.id ? "primary" : "secondary"} size="sm" onClick={() => setFilterSubj(s.id)}>{s.name}</Btn>
        ))}
      </div>

      {/* Sessions list */}
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {sessions.length === 0 && <EmptyState icon={CalendarCheck} message="No sessions found" />}
        {sessions.map(session => {
          const theme = getSubjectTheme(session.subject);
          const students = getStudentsForSubject(session.subject);
          const rec = state.attendance[session.id] || {};
          const presentCount = Object.values(rec).filter(v => v === "present").length;
          const lateCount = Object.values(rec).filter(v => v === "late").length;
          const absentCount = Object.values(rec).filter(v => v === "absent").length;
          const unmarked = students.length - presentCount - lateCount - absentCount;
          const isExpanded = expanded === session.id;
          const isToday = session.date === TODAY;

          return (
            <Card key={session.id} elevated style={{ borderLeft: `3px solid ${isToday ? T.accent : theme.accent}` }}>
              {/* Session header — clickable to expand */}
              <div onClick={() => setExpanded(isExpanded ? null : session.id)} style={{ cursor: "pointer", display: "flex", alignItems: "center", gap: 14 }}>
                <div style={{ width: 44, height: 44, borderRadius: T.r2, background: theme.bg, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <CalendarCheck size={20} weight="duotone" color={theme.accent} />
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ fontSize: 14, fontWeight: 650, color: T.text }}>{formatDate(session.date)}</span>
                    {isToday && <Badge color={T.accentText} bg={T.accentLight}>Today</Badge>}
                    {unmarked > 0 && isToday && <Badge color={T.warning} bg={T.warningBg}>{unmarked} unmarked</Badge>}
                  </div>
                  <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4, flexWrap: "wrap" }}>
                    <SubjectBadge subjectId={session.subject} small />
                    <span style={{ fontSize: 12, color: T.textTer }}>{session.time}</span>
                    {session.notes && <span style={{ fontSize: 12, color: T.textSec }}>· {session.notes}</span>}
                  </div>
                </div>
                <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                  {presentCount > 0 && <Badge color={T.success} bg={T.successBg} style={{ fontSize: 10 }}><CheckCircle size={12} weight="fill" /> {presentCount}</Badge>}
                  {lateCount > 0 && <Badge color={T.warning} bg={T.warningBg} style={{ fontSize: 10 }}><Clock size={12} weight="fill" /> {lateCount}</Badge>}
                  {absentCount > 0 && <Badge color={T.danger} bg={T.dangerBg} style={{ fontSize: 10 }}><XCircle size={12} weight="fill" /> {absentCount}</Badge>}
                  <CaretRight size={16} weight="bold" color={T.textTer} style={{ transform: isExpanded ? "rotate(90deg)" : "none", transition: "transform 0.15s" }} />
                </div>
              </div>

              {/* Expanded — student attendance controls */}
              {isExpanded && (
                <div style={{ marginTop: 16, paddingTop: 16, borderTop: `1px solid ${T.border}` }}>
                  {/* Inline notes editing */}
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14 }}>
                    <Notebook size={14} weight="bold" color={T.textTer} />
                    {editingNotes === session.id ? (
                      <div style={{ display: "flex", gap: 8, flex: 1 }}>
                        <Input value={session.notes} onChange={(v) => dispatch({ type: "UPDATE_SESSION_NOTES", payload: { id: session.id, notes: v } })} placeholder="Add session notes..." style={{ flex: 1 }} />
                        <Btn size="sm" variant="secondary" onClick={() => { setEditingNotes(null); dispatch({ type: "ADD_TOAST", payload: { message: "Notes saved", variant: "success" } }); }}>Done</Btn>
                      </div>
                    ) : (
                      <button onClick={() => setEditingNotes(session.id)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 12, color: session.notes ? T.textSec : T.textTer, fontStyle: session.notes ? "normal" : "italic", padding: "4px 0" }}>
                        {session.notes || "Add notes..."}
                      </button>
                    )}
                  </div>

                  <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12, padding: "8px 12px", background: T.bgMuted, borderRadius: T.r2, fontSize: 11, color: T.textTer }}>
                    <span style={{ fontWeight: 600 }}>Legend:</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><CheckCircle size={13} weight="fill" color={T.success} /> Present</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><Clock size={13} weight="fill" color={T.warning} /> Late</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 4 }}><XCircle size={13} weight="fill" color={T.danger} /> Absent</span>
                  </div>

                  <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                    {students.map(student => {
                      const status = rec[student.id];
                      return (
                        <div key={student.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", borderRadius: T.r2, background: status === "present" ? `${T.successBg}80` : status === "late" ? `${T.warningBg}80` : status === "absent" ? `${T.dangerBg}80` : T.bgMuted, transition: "background 0.2s", border: `1px solid ${status === "present" ? T.success + "30" : status === "late" ? T.warning + "30" : status === "absent" ? T.danger + "30" : T.border}` }}>
                          <div style={{ width: 32, height: 32, borderRadius: "50%", background: `linear-gradient(135deg, ${T.accent}, #3F51EC)`, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 700, fontSize: 12, flexShrink: 0 }}>
                            {student.name.split(" ").map(n => n[0]).join("")}
                          </div>
                          <span style={{ flex: 1, fontSize: 13, fontWeight: 600, color: T.text }}>{student.name}</span>
                          {!status && <span style={{ fontSize: 11, color: T.textTer, fontStyle: "italic" }}>Not marked</span>}
                          <div style={{ display: "flex", gap: 4 }}>
                            {[
                              { key: "present", icon: CheckCircle, activeColor: T.success, activeBg: T.successBg },
                              { key: "late", icon: Clock, activeColor: T.warning, activeBg: T.warningBg },
                              { key: "absent", icon: XCircle, activeColor: T.danger, activeBg: T.dangerBg },
                            ].map(btn => (
                              <button key={btn.key}
                                onClick={() => dispatch({ type: "MARK_ATTENDANCE", payload: { sessionId: session.id, studentId: student.id, status: status === btn.key ? null : btn.key } })}
                                onMouseEnter={(e) => { if (status !== btn.key) e.currentTarget.style.background = btn.activeBg; }}
                                onMouseLeave={(e) => { if (status !== btn.key) e.currentTarget.style.background = "transparent"; }}
                                style={{ width: 34, height: 34, borderRadius: T.r1, border: `1.5px solid ${status === btn.key ? btn.activeColor : T.border}`, background: status === btn.key ? btn.activeBg : "transparent", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", transition: "all 0.15s" }}>
                                <btn.icon size={16} weight={status === btn.key ? "fill" : "regular"} color={status === btn.key ? btn.activeColor : T.textTer} />
                              </button>
                            ))}
                          </div>
                        </div>
                      );
                    })}
                  </div>

                  {/* Quick mark all */}
                  <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
                    <Btn size="sm" variant="secondary" onClick={() => { students.forEach(st => dispatch({ type: "MARK_ATTENDANCE", payload: { sessionId: session.id, studentId: st.id, status: "present" } })); dispatch({ type: "ADD_TOAST", payload: { message: "All marked present", variant: "success" } }); }}>
                      <CheckCircle size={14} weight="fill" color={T.success} /> Mark All Present
                    </Btn>
                  </div>
                </div>
              )}
            </Card>
          );
        })}
      </div>
    </div>
  );
}

/* ━━━ LEADERBOARD PAGE ━━━ */
function Leaderboard({ state, dispatch }) {
  const ranked = [...state.students]
    .map(s => ({ ...s, xp: calcStudentXP(s, state), badges: getStudentBadges(s, state) }))
    .sort((a, b) => b.xp - a.xp);

  const [lbFilter, setLbFilter] = React.useState("all");
  const filteredRanked = lbFilter === "all" ? ranked : ranked.filter(s => s.subjects && s.subjects.includes(lbFilter));

  return (
    <div>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6 }}>
          <div style={{ width: 40, height: 40, borderRadius: T.r2, background: "linear-gradient(135deg, #D4A254, #F0C060)", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 4px 12px rgba(212,162,84,0.3)" }}>
            <Trophy size={20} weight="fill" color="#fff" />
          </div>
          <div>
            <h1 style={{ fontSize: 26, fontWeight: 800, background: T.gradPrimary, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", margin: 0, letterSpacing: "-0.03em", fontFamily: "'Bricolage Grotesque', sans-serif" }}>Class Leaderboard</h1>
            <p style={{ color: T.textSec, margin: 0, fontSize: 13 }}>XP earned through quizzes, attendance &amp; engagement</p>
          </div>
        </div>
        {/* XP info strip */}
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 14 }}>
          {[
            { emoji: "⚡", text: "10 XP / quiz answer" },
            { emoji: "💯", text: "+50 XP perfect score" },
            { emoji: "✅", text: "20 XP / session" },
            { emoji: "📚", text: "5 XP / resource" },
          ].map(x => (
            <div key={x.text} style={{ display: "flex", alignItems: "center", gap: 5, background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: 20, padding: "5px 12px", fontSize: 11, fontWeight: 600, color: T.textSec }}>
              <span>{x.emoji}</span><span>{x.text}</span>
            </div>
          ))}
        </div>
        {/* Subject filter tabs */}
        <div style={{ display: "flex", gap: 6, marginTop: 14, flexWrap: "wrap" }}>
          {[{ id: "all", label: "All Subjects" }, ...SUBJECTS.map(s => ({ id: s.id, label: s.name }))].map(tab => (
            <button key={tab.id} onClick={() => setLbFilter(tab.id)} style={{ padding: "6px 14px", borderRadius: 20, border: `1px solid ${lbFilter === tab.id ? T.accent : T.border}`, background: lbFilter === tab.id ? T.accentLight : T.bgCard, color: lbFilter === tab.id ? T.accentText : T.textSec, fontSize: 12, fontWeight: 600, cursor: "pointer", transition: "all 0.15s" }}>
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Podium */}
      {ranked.length >= 3 && (
        <div style={{ background: `linear-gradient(135deg, #0F172A 0%, #1E2A4A 50%, #2D3A8C 100%)`, borderRadius: T.r4, padding: "32px 24px 0", marginBottom: 28, overflow: "hidden", position: "relative" }}>
          <div style={{ position: "absolute", inset: 0, background: "radial-gradient(circle at 50% 20%, rgba(212,162,84,0.1), transparent 60%)" }} />
          <div style={{ textAlign: "center", marginBottom: 20, position: "relative", zIndex: 1 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: "#D4A254", letterSpacing: 1.2, textTransform: "uppercase" }}>Class Podium</div>
          </div>
          <div style={{ display: "flex", justifyContent: "center", alignItems: "flex-end", gap: 0 }}>
            <PodiumCard student={ranked[1]} rank={2} xp={ranked[1].xp} />
            <PodiumCard student={ranked[0]} rank={1} xp={ranked[0].xp} />
            <PodiumCard student={ranked[2]} rank={3} xp={ranked[2].xp} />
          </div>
        </div>
      )}

      {/* Full rankings */}
      <Card elevated style={{ padding: 0, overflow: "hidden", marginBottom: 28 }}>
        <div style={{ padding: "16px 24px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <h3 style={{ margin: 0, fontWeight: 700, fontSize: 16 }}>Full Rankings</h3>
          <span style={{ fontSize: 12, color: T.textTer, fontWeight: 500 }}>{filteredRanked.length} student{filteredRanked.length !== 1 ? "s" : ""}</span>
        </div>
        {filteredRanked.map((student, idx) => {
          const lv = getLevel(student.xp);
          const rankDisplay = idx === 0 ? "🥇" : idx === 1 ? "🥈" : idx === 2 ? "🥉" : `#${idx + 1}`;
          return (
            <div key={student.id} style={{ display: "flex", alignItems: "center", gap: 16, padding: "16px 24px", borderBottom: idx < filteredRanked.length - 1 ? `1px solid ${T.border}` : "none", background: idx === 0 ? `${lv.bg}99` : T.bgCard, transition: "background 0.15s" }}
              onMouseEnter={e => { if (idx !== 0) e.currentTarget.style.background = T.bgMuted; }}
              onMouseLeave={e => { if (idx !== 0) e.currentTarget.style.background = T.bgCard; }}>
              <div style={{ width: 40, fontSize: idx < 3 ? 22 : 13, fontWeight: 700, color: idx < 3 ? "inherit" : T.textSec, textAlign: "center", flexShrink: 0 }}>{rankDisplay}</div>
              <StudentAvatar student={student} size={44} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                  <span style={{ fontWeight: 700, fontSize: 14 }}>{student.name}</span>
                  {student.badges.map(b => <span key={b.id} title={`${b.name}: ${b.desc}`} style={{ fontSize: 15 }}>{b.emoji}</span>)}
                </div>
                <XPBar xp={student.xp} compact />
              </div>
              <div style={{ textAlign: "right", flexShrink: 0 }}>
                <div style={{ fontWeight: 800, fontSize: 22, color: lv.color, fontFamily: "'JetBrains Mono', monospace" }}>{student.xp}</div>
                <div style={{ fontSize: 11, color: T.textTer }}>total XP</div>
              </div>
            </div>
          );
        })}
      </Card>

      {/* Achievements gallery */}
      <h2 style={{ fontSize: 20, fontWeight: 800, color: T.text, margin: "0 0 16px", letterSpacing: "-0.03em", fontFamily: "'Bricolage Grotesque', sans-serif" }}>Achievements Gallery</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 14 }}>
        {ranked.map(student => {
          const lv = getLevel(student.xp);
          return (
            <Card key={student.id} elevated style={{ padding: 20 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
                <StudentAvatar student={student} size={40} />
                <div>
                  <div style={{ fontWeight: 700 }}>{student.name}</div>
                  <div style={{ fontSize: 11, color: T.textTer }}>{student.badges.length} / {BADGE_DEFS.length} badges earned</div>
                </div>
              </div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                {BADGE_DEFS.map(b => {
                  const earned = student.badges.some(sb => sb.id === b.id);
                  return <BadgeChip key={b.id} badge={b} earned={earned} size="sm" />;
                })}
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

/* ━━━ COMMUNITY PAGE ━━━ */
function Community({ state, dispatch }) {
  const [filter, setFilter] = useState("all");
  const [showNewPost, setShowNewPost] = useState(false);
  const [expandedComments, setExpandedComments] = useState(new Set());
  const [newComment, setNewComment] = useState({});
  const [newPost, setNewPost] = useState({ title: "", content: "", subject: "", isAnnouncement: false });

  const filterTabs = [
    { id: "all", label: "All Posts" },
    { id: "announcements", label: "📢 Announcements" },
    ...SUBJECTS.map(s => ({ id: s.id, label: s.name })),
  ];

  const filteredPosts = [...(state.posts || [])]
    .sort((a, b) => {
      if (a.pinned && !b.pinned) return -1;
      if (!a.pinned && b.pinned) return 1;
      return new Date(b.createdAt) - new Date(a.createdAt);
    })
    .filter(p => {
      if (filter === "all") return true;
      if (filter === "announcements") return p.isAnnouncement;
      return p.subject === filter;
    });

  const toggleComments = (postId) => {
    const next = new Set(expandedComments);
    if (next.has(postId)) next.delete(postId); else next.add(postId);
    setExpandedComments(next);
  };

  const handleAddComment = (postId) => {
    const text = (newComment[postId] || "").trim();
    if (!text) return;
    dispatch({ type: "ADD_COMMENT", payload: { postId, comment: { author: "Jeremy", content: text } } });
    setNewComment(prev => ({ ...prev, [postId]: "" }));
  };

  const handleAddPost = () => {
    if (!newPost.title.trim() || !newPost.content.trim()) return;
    dispatch({ type: "ADD_POST", payload: { ...newPost, author: "Jeremy", authorType: "tutor" } });
    setNewPost({ title: "", content: "", subject: "", isAnnouncement: false });
    setShowNewPost(false);
    dispatch({ type: "ADD_TOAST", payload: { message: "Post published to the community!", variant: "success" } });
  };

  return (
    <div>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: 26, fontWeight: 700, background: "linear-gradient(135deg, #0F172A, #2D3A8C)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", margin: 0, letterSpacing: -0.3, fontFamily: "'Bricolage Grotesque', sans-serif" }}>Community</h1>
          <p style={{ color: T.textSec, margin: "4px 0 0", fontSize: 14 }}>Announcements, discussions, and study tips from the class</p>
        </div>
        <Btn onClick={() => setShowNewPost(!showNewPost)}><Plus size={15} weight="bold" /> New Post</Btn>
      </div>

      {/* New post form */}
      {showNewPost && (
        <Card elevated style={{ marginBottom: 20, padding: 22 }}>
          <h3 style={{ margin: "0 0 16px", fontWeight: 700, fontSize: 15 }}>Create Post</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            <Input value={newPost.title} onChange={v => setNewPost(p => ({ ...p, title: v }))} placeholder="Post title..." />
            <Textarea value={newPost.content} onChange={v => setNewPost(p => ({ ...p, content: v }))} placeholder="What would you like to share with the class?" rows={4} />
            <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
              <Select value={newPost.subject} onChange={v => setNewPost(p => ({ ...p, subject: v }))} placeholder="Tag a subject (optional)" options={SUBJECTS.map(s => ({ value: s.id, label: s.name }))} style={{ flex: 1, minWidth: 180 }} />
              <label style={{ display: "flex", alignItems: "center", gap: 6, cursor: "pointer", fontSize: 13, color: T.textSec, flexShrink: 0 }}>
                <input type="checkbox" checked={newPost.isAnnouncement} onChange={e => setNewPost(p => ({ ...p, isAnnouncement: e.target.checked }))} />
                Mark as Announcement
              </label>
            </div>
            <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
              <Btn variant="secondary" onClick={() => setShowNewPost(false)}>Cancel</Btn>
              <Btn onClick={handleAddPost} disabled={!newPost.title.trim() || !newPost.content.trim()}><Megaphone size={14} weight="bold" /> Publish</Btn>
            </div>
          </div>
        </Card>
      )}

      {/* Stats strip */}
      <div style={{ display: "flex", gap: 20, marginBottom: 20 }}>
        {[
          { label: "Total Posts", value: (state.posts || []).length },
          { label: "Announcements", value: (state.posts || []).filter(p => p.isAnnouncement).length },
          { label: "Total Comments", value: (state.posts || []).reduce((sum, p) => sum + p.comments.length, 0) },
        ].map(s => (
          <div key={s.label} style={{ background: T.bgCard, border: `1px solid ${T.border}`, borderRadius: T.r2, padding: "10px 18px", display: "flex", gap: 10, alignItems: "center" }}>
            <div style={{ fontWeight: 800, fontSize: 20, color: T.accent }}>{s.value}</div>
            <div style={{ fontSize: 12, color: T.textSec }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Filter tabs */}
      <div style={{ display: "flex", gap: 6, marginBottom: 20, flexWrap: "wrap" }}>
        {filterTabs.map(f => (
          <button key={f.id} onClick={() => setFilter(f.id)} style={{ padding: "6px 14px", borderRadius: T.r2, border: `1.5px solid ${filter === f.id ? T.accent : T.border}`, background: filter === f.id ? T.accentLight : T.bgCard, color: filter === f.id ? T.accentText : T.textSec, fontSize: 12, fontWeight: filter === f.id ? 700 : 500, cursor: "pointer", transition: "all 0.15s", whiteSpace: "nowrap" }}>
            {f.label}
          </button>
        ))}
      </div>

      {/* Post list */}
      <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
        {filteredPosts.length === 0 && (
          <div style={{ textAlign: "center", padding: "60px 20px", color: T.textTer }}>
            <EmptyStateIllustration type="learning" size={100} />
            <ChatCircle size={40} weight="duotone" color={T.textTer} style={{ marginTop: 12 }} />
            <div style={{ fontSize: 15, fontWeight: 600, marginTop: 12 }}>No posts here yet</div>
            <div style={{ fontSize: 13, marginTop: 4 }}>Be the first to start a discussion!</div>
          </div>
        )}
        {filteredPosts.map(post => {
          const commentsOpen = expandedComments.has(post.id);
          const subjectTheme = post.subject ? getSubjectTheme(post.subject) : null;
          return (
            <Card key={post.id} elevated style={{ padding: 0, overflow: "hidden", borderLeft: post.pinned ? `3px solid ${T.accent}` : post.isAnnouncement ? `3px solid #E07800` : "none" }}>
              {/* Post header + body */}
              <div style={{ padding: "18px 20px 14px" }}>
                <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 12 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    {post.authorType === "tutor"
                      ? <div style={{ width: 38, height: 38, borderRadius: "50%", background: `linear-gradient(135deg, ${T.accent}, #3F51EC)`, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 700, fontSize: 14, flexShrink: 0 }}>J</div>
                      : <StudentAvatar student={state.students.find(s => s.id === post.studentId)} size={38} radius="50%" />
                    }
                    <div>
                      <div style={{ display: "flex", alignItems: "center", gap: 5, flexWrap: "wrap" }}>
                        <span style={{ fontWeight: 700, fontSize: 13 }}>{post.author}</span>
                        {post.authorType === "tutor" && <span style={{ fontSize: 10, fontWeight: 700, color: T.accentText, background: T.accentLight, padding: "2px 6px", borderRadius: 20 }}>Tutor</span>}
                        {post.isAnnouncement && <span style={{ fontSize: 10, fontWeight: 700, color: "#92400E", background: "#FEF3C7", padding: "2px 6px", borderRadius: 20 }}>📢 Announcement</span>}
                        {post.pinned && <span style={{ fontSize: 10, color: T.accent, fontWeight: 600 }}>📌 Pinned</span>}
                      </div>
                      <div style={{ fontSize: 11, color: T.textTer }}>{formatDate(post.createdAt)}</div>
                    </div>
                  </div>
                  <div style={{ display: "flex", gap: 6, alignItems: "center", flexShrink: 0 }}>
                    {post.subject && subjectTheme && (
                      <span style={{ fontSize: 10, fontWeight: 700, color: subjectTheme.text, background: subjectTheme.bg, padding: "3px 8px", borderRadius: 20 }}>{getSubject(post.subject)?.name}</span>
                    )}
                    <button onClick={() => dispatch({ type: "PIN_POST", payload: post.id })} title={post.pinned ? "Unpin" : "Pin post"} style={{ background: "none", border: "none", cursor: "pointer", padding: 4, color: post.pinned ? T.accent : T.textTer, fontSize: 15, lineHeight: 1 }}>📌</button>
                  </div>
                </div>
                <h3 style={{ margin: "0 0 8px", fontSize: 15, fontWeight: 700, color: T.text, lineHeight: 1.4 }}>{post.title}</h3>
                <p style={{ margin: 0, fontSize: 13, color: T.textSec, lineHeight: 1.75, whiteSpace: "pre-wrap" }}>{post.content}</p>
              </div>

              {/* Reactions bar */}
              <div style={{ padding: "10px 20px", borderTop: `1px solid ${T.border}`, display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap" }}>
                {COMMUNITY_REACTIONS.map(emoji => {
                  const count = (post.reactions?.[emoji] || []).length;
                  const reacted = (post.reactions?.[emoji] || []).includes(0);
                  return (
                    <button key={emoji} onClick={() => dispatch({ type: "TOGGLE_REACTION", payload: { postId: post.id, emoji } })} style={{ padding: "4px 10px", borderRadius: 20, border: `1.5px solid ${reacted ? T.accent : T.border}`, background: reacted ? T.accentLight : T.bgCard, cursor: "pointer", fontSize: 13, display: "flex", alignItems: "center", gap: 4, color: reacted ? T.accentText : T.textSec, fontWeight: reacted ? 700 : 400, transition: "all 0.15s" }}>
                      {emoji}{count > 0 && <span style={{ fontSize: 11 }}>{count}</span>}
                    </button>
                  );
                })}
                <button onClick={() => toggleComments(post.id)} style={{ marginLeft: "auto", background: "none", border: `1px solid ${T.border}`, borderRadius: 20, cursor: "pointer", fontSize: 12, color: T.textSec, display: "flex", alignItems: "center", gap: 5, padding: "5px 12px", transition: "all 0.15s" }}>
                  <ChatCircle size={14} weight="duotone" /> {post.comments.length} {post.comments.length === 1 ? "comment" : "comments"}
                </button>
              </div>

              {/* Comments section */}
              {commentsOpen && (
                <div style={{ background: T.bgMuted, borderTop: `1px solid ${T.border}`, padding: "14px 20px 16px" }}>
                  <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                    {post.comments.map(comment => (
                      <div key={comment.id} style={{ display: "flex", gap: 10, alignItems: "flex-start" }}>
                        {comment.studentId
                          ? <StudentAvatar student={state.students.find(s => s.id === comment.studentId)} size={30} radius="50%" />
                          : <div style={{ width: 30, height: 30, borderRadius: "50%", background: `linear-gradient(135deg, ${T.accent}, #3F51EC)`, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 700, fontSize: 11, flexShrink: 0 }}>J</div>
                        }
                        <div style={{ flex: 1, background: T.bgCard, borderRadius: T.r2, padding: "10px 14px", border: `1px solid ${T.border}` }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
                            <span style={{ fontWeight: 700, fontSize: 12 }}>{comment.author}</span>
                            {comment.author === "Jeremy" && <span style={{ fontSize: 9, fontWeight: 700, color: T.accentText, background: T.accentLight, padding: "1px 5px", borderRadius: 20 }}>Tutor</span>}
                            <span style={{ fontSize: 10, color: T.textTer }}>{formatDate(comment.createdAt)}</span>
                          </div>
                          <p style={{ margin: 0, fontSize: 13, color: T.text, lineHeight: 1.6 }}>{comment.content}</p>
                        </div>
                      </div>
                    ))}
                    {/* Add comment */}
                    <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4 }}>
                      <div style={{ width: 30, height: 30, borderRadius: "50%", background: `linear-gradient(135deg, ${T.accent}, #3F51EC)`, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 700, fontSize: 11, flexShrink: 0 }}>J</div>
                      <Input value={newComment[post.id] || ""} onChange={v => setNewComment(prev => ({ ...prev, [post.id]: v }))} placeholder="Reply as Jeremy..." style={{ flex: 1 }} />
                      <Btn size="sm" onClick={() => handleAddComment(post.id)} disabled={!(newComment[post.id] || "").trim()}>Post</Btn>
                    </div>
                  </div>
                </div>
              )}
            </Card>
          );
        })}
      </div>
    </div>
  );
}

/* ━━━ LIVE INFOGRAPHICS ━━━ */

const GP2_OVERVIEW = [
  { code: "SAQ", label: "Short-Answer Questions", marks: "9–11", time: "25 min", color: "#216ef4", pct: 22 },
  { code: "NIT", label: "New Item Type / Connections", marks: "4–6", time: "10 min", color: "#6660B9", pct: 10 },
  { code: "SUM", label: "Summary Question", marks: "8", time: "25 min", color: "#17a2b8", pct: 16 },
  { code: "AQ",  label: "Application Question", marks: "12", time: "25 min", color: "#E07800", pct: 24 },
  { code: "READ",label: "Reading Passages",  marks: "—",   time: "10 min", color: "#8A96B0", pct: 14 },
  { code: "CHK", label: "Checking",          marks: "—",   time: "5 min",  color: "#8A96B0", pct: 14 },
];

const GP2_QTYPES = [
  {
    id: "q1", code: "Q1", section: "A", sectionLabel: "Literal", badge: "Most common",
    title: "Direct Paraphrasing", subtitle: "Locate → Restate in your own words",
    color: "#216ef4", bg: "#E4EFFE", emoji: "📝",
    commandWords: ["WHY = reasons/causes", "HOW = methods/processes", "WHAT = definitions"],
    steps: [
      { n: 1, title: "Identify the command word", body: "WHY → trace causal signposts (because, as, since, due to). HOW → trace sequential connectors (first, then, through). WHAT → find the elaboration or definition near the term." },
      { n: 2, title: "Locate the answer", body: "Find the keyword(s) from the question in the passage. Read the sentences BEFORE and AFTER — the answer is almost always there." },
      { n: 3, title: "Apply APT Paraphrasing", body: "Accuracy: replace with synonyms of the same connotation. Precision: capture intensity — 'grief' → 'anguish', not 'sadness'. Thoroughness: retain cause-effect, compare-contrast, and specific subject." },
      { n: 4, title: "Write and check", body: "One complete sentence per point. Do not start by lifting the original phrase. Ensure grammatical fluency. Verify the answer addresses the command word." },
    ],
    templates: [
      { label: "WHY (1 reason)", t: "The author explains this is because [paraphrased cause], which results in [paraphrased effect]." },
      { label: "HOW (process)",  t: "The author describes how [subject] first [step 1], then [step 2], in order to [purpose]." },
      { label: "WHAT (definition)", t: "[Concept] refers to [paraphrased explanation in context], suggesting that [implication]." },
    ],
    eg: {
      passage: '"…because if everyone travels within the bounds of given rules, no horizons will ever be expanded."',
      weak: '"We should only break rules to better society." — Too vague. Loses the cause-effect and the idea of expanding knowledge.',
      strong: '"The author sees the advantage as helping to widen people\'s knowledge and perspectives of the world around them, thereby facilitating the progress of society."',
      why: '"horizons expanded" → "widen people\'s knowledge and perspectives" captures literal + contextual meaning. The cause-effect chain is preserved.',
    },
  },
  {
    id: "q2", code: "Q2", section: "A", sectionLabel: "Literal", badge: "Similarities / Differences",
    title: "Comparison Questions", subtitle: "Aligned or opposing ideas between two subjects",
    color: "#216ef4", bg: "#E4EFFE", emoji: "⚖️",
    commandWords: ["Similarities: aligned ideas", "Differences: same criterion, contrasting outcomes"],
    steps: [
      { n: 1, title: "Identify the two subjects", body: "Clearly name Subject A and Subject B from the question. The question will specify what to compare — attitude, approach, outcome, etc." },
      { n: 2, title: "Locate aligned or contrasting ideas", body: "For similarities: find ideas that both subjects share. For differences: find the SAME criterion with opposing outcomes. Each paired answer = 1 mark." },
      { n: 3, title: "Structure your answer clearly", body: "Signal your answer explicitly. Never leave the contrast implied. Each pair must show a clear contrast based on the same criterion." },
    ],
    templates: [
      { label: "Similarity", t: "Both [Subject A] and [Subject B] [shared paraphrased idea]." },
      { label: "Difference (1 mark)", t: "While [Subject A] [paraphrased idea A], [Subject B] [paraphrased contrasting idea B]." },
    ],
    eg: {
      passage: 'Criterion: VALUE OF BEAUTY — comparing the author\'s view vs. the public\'s view.',
      weak: '"Subject A thinks beauty is bad. Subject B thinks beauty is good." — Criterion not stated, no paraphrasing.',
      strong: '"While the author views beauty as a burden that causes suffering, the public regards beauty as a blessing that brings admiration and social advantage."',
      why: 'Same criterion (value of beauty) with a clear contrast visible in both halves. Both ideas are paraphrased, not lifted.',
    },
  },
  {
    id: "q3", code: "Q3", section: "B1", sectionLabel: "Inferential", badge: "Intensifiers & Qualifiers",
    title: "Use of Vocabulary", subtitle: "Function of a specific word in context",
    color: "#6660B9", bg: "#EEEAFF", emoji: "🔍",
    commandWords: ['"What is the effect of…"', '"Why does the author use the word…"'],
    steps: [
      { n: 1, title: "Identify the word's type", body: "Intensifier: emphasises degree/extent (significantly, even, greatly). Qualifier: limits a claim (almost, largely, merely). 'Even': emphasises surprising extreme extent. 'Only': sole viable option. 'Mere': insignificance or underestimation." },
      { n: 2, title: "State the FUNCTION", body: "What role does this word play? 'The author uses [word] to emphasise the [extremity / surprising nature / extent / insignificance] of [the issue]…'" },
      { n: 3, title: "Provide the CONTEXT", body: "What specifically is being emphasised? 'such that / so much so that / to the point that [paraphrased contextual explanation].' Answers without context will NOT score." },
    ],
    templates: [
      { label: "Full template", t: "The author uses [word/phrase] to emphasise [the extremity / surprising nature / extent / insignificance] of [the issue], such that [paraphrased contextual explanation — what is surprising or qualified]." },
    ],
    eg: {
      passage: '"Anxiety is on the rise in all age groups, such that even toddlers are not immune." (line 7)',
      weak: '"The word \'even\' is used to emphasise the author\'s point." — No context. Will not score.',
      strong: '"The author uses the word \'even\' to emphasise the surprising extremity of the problem, such that very young children — who we would not normally expect to experience anxiety — are also not spared from its effects."',
      why: 'Function: "emphasise the surprising extremity". Context: explains WHO is affected and WHY this is surprising. Both components present.',
    },
  },
  {
    id: "q4a", code: "Q4A", section: "B2", sectionLabel: "Inferential", badge: "Typographical devices",
    title: "Punctuation & Devices", subtitle: "Effect of inverted commas, brackets, repetition, dashes…",
    color: "#6660B9", bg: "#EEEAFF", emoji: "🖋️",
    commandWords: ['"Explain the effect of…"', '"Why does the author use…"'],
    steps: [
      { n: 1, title: "Name the device", body: "Inverted commas / Quotation marks · Brackets / Parentheses · Repetition · Ellipsis (…) · Italics · Rhetorical questions · Dashes (—)." },
      { n: 2, title: "State the FUNCTION", body: "Inverted commas: question/challenge whether the word truly applies (often ironic). Repetition: emphasise the idea carried by the repeated word. Ellipsis: dramatic emphasis or endless continuation. Dashes: dramatic pause before a key idea." },
      { n: 3, title: "Provide REASON/CONTEXT", body: "Why is this device used here? What does it convey in this specific passage? Naming the device alone does NOT earn marks." },
    ],
    templates: [
      { label: "Inverted commas", t: "[Author] uses inverted commas around [word] to question/challenge whether [word] truly applies here, because [contextual reason — why the term is being disputed or used ironically]." },
      { label: "Repetition", t: "[Author] repeats [word/phrase] to emphasise [contextual idea conveyed by the repeated word]." },
      { label: "Rhetorical Qs", t: "The author poses a series of rhetorical questions to provoke thought in the reader about [specific issue], and to progressively build the argument that [paraphrased claim]." },
    ],
    eg: {
      passage: '"Rule-breaking may have another \'positive\' association — it may be perceived as a form of solidarity."',
      weak: '"The inverted commas show that this is not really positive." — Insufficient. No context.',
      strong: '"The author places \'positive\' in inverted commas to challenge whether rule-breaking can genuinely be regarded as beneficial, since the word is used ironically to suggest that the so-called \'positive\' associations are dubious or contested."',
      why: 'Function (challenge/question) + contextual explanation of why the irony is significant = full marks.',
    },
  },
  {
    id: "q4c", code: "Q4C", section: "B2", sectionLabel: "Inferential", badge: "Figurative language",
    title: "Metaphor, Analogy, Paradox, Irony", subtitle: "Literal image → contextual meaning",
    color: "#6660B9", bg: "#EEEAFF", emoji: "🎭",
    commandWords: ['"Explain the metaphor in…"', '"What does the author mean by…"', '"What is paradoxical about…"'],
    steps: [
      { n: 1, title: "Identify the device type", body: "Metaphor/Analogy: comparison attributing qualities without 'like/as'. Paradox: self-contradictory statement that reveals a truth. Irony: contrast between expectation and reality." },
      { n: 2, title: "State the LITERAL meaning", body: "What does the image/object literally refer to? For metaphors: 'X literally refers to [literal quality]…'" },
      { n: 3, title: "Map to CONTEXTUAL meaning", body: "Use 'Just as [literal meaning], so too does [subject] [contextual quality].' For paradox: 'While one would expect [expected], it is paradoxical that [actual], because [reason].' For irony: 'One would expect [X], yet in reality [Y], which is ironic because [reason].'" },
    ],
    templates: [
      { label: "Metaphor / Analogy", t: "'[Object]' literally refers to [literal quality]. Just as [literal meaning], so too does [subject] [contextual quality], suggesting [implication]." },
      { label: "Paradox", t: "While one would expect [expected outcome], it is paradoxical that [actual contradictory reality], because [reason for the contradiction]." },
      { label: "Irony", t: "One would expect [X], yet in reality [contrasting Y occurs], which is ironic because [reason the gap is significant]." },
    ],
    eg: {
      passage: '"Nothing matches the tentacles of the internet for its insidious spread and reach."',
      weak: '"The author compares the internet to a creature with tentacles to show it is dangerous." — Too vague. No literal meaning, no contextual quality.',
      strong: '"\'Tentacles\' literally refers to the long, flexible limbs of creatures like octopuses that extend in multiple directions to grip and entrap their prey. Just as tentacles spread imperceptibly and ensnare without warning, so too does the internet penetrate every corner of life in a hidden and harmful way, making it impossible to escape once your personal data has been released into it."',
      why: 'Literal meaning → contextual quality. The "just as... so too" connector links both halves explicitly.',
    },
  },
  {
    id: "q4d", code: "Q4D", section: "B2", sectionLabel: "Inferential", badge: "Contextual meaning",
    title: "Explain the Meaning Of…", subtitle: "Full contextual paraphrase (3-part answer)",
    color: "#6660B9", bg: "#EEEAFF", emoji: "💬",
    commandWords: ['"Explain the meaning of…"', '"What does the phrase… mean?"', '"In your own words, explain…"'],
    steps: [
      { n: 1, title: "Paraphrase (Part 1)", body: "Replace the word or phrase with a precise synonym. Apply APT principles. Shows the examiner you understand the core meaning without relying on the original wording." },
      { n: 2, title: "Contextualise (Part 2)", body: "Explain what the word/phrase specifically means given the subject matter. State who it refers to and what situation it describes. Prevents vague answers that could apply to any passage." },
      { n: 3, title: "Implication (Part 3)", body: "State what the expression implies or suggests — the attitude, tone, or judgement conveyed. Required for full marks on higher-value questions." },
    ],
    templates: [
      { label: "Literal/concrete", t: "[Word/phrase] means [precise paraphrase]. In this context, it refers to [contextual explanation of who/what/situation], suggesting that [implication or attitude conveyed]." },
      { label: "Figurative", t: "The expression [quote] literally refers to [literal image]. Here, it conveys that [contextual meaning], suggesting [implication or attitude]." },
    ],
    eg: {
      passage: '"social media has become an echo chamber"',
      weak: '"An echo chamber is a place where sounds repeat. Social media is like this." — Only literal meaning. No contextual unpacking.',
      strong: '"An \'echo chamber\' literally refers to a space that reflects the same sound repeatedly. Here, it suggests that social media platforms amplify only the views users already hold, insulating them from opposing perspectives and reinforcing existing biases, implying that users become increasingly closed-minded over time."',
      why: 'Part 1: paraphrase. Part 2: specific contextual meaning (social media/views/biases). Part 3: implication for users. All three parts present.',
    },
  },
  {
    id: "q5", code: "Q5", section: "B3", sectionLabel: "Structural", badge: "Intro & Conclusion",
    title: "Stylistic Devices in Structure", subtitle: "Opening/closing devices and their purpose",
    color: "#17a2b8", bg: "#E0F6F9", emoji: "🏛️",
    commandWords: ['"What is the purpose of the opening…"', '"How does the conclusion…"'],
    steps: [
      { n: 1, title: "Identify the device", body: "Anecdote · Analogy · Quote · Rhetorical question · Return to the opening device (circularity) · Call to action · Lingering question." },
      { n: 2, title: "State the FUNCTION", body: "Introduction: establish relevance, engage the reader, contextualise the issue, set up the argument. Conclusion: summarise, reiterate, strengthen, create urgency/circularity." },
      { n: 3, title: "Link to the MAIN CLAIM", body: "Always connect the device to the author's central argument. 'by showing that [paraphrased contextual point linked to the author's main claim]'." },
    ],
    templates: [
      { label: "Introduction device", t: "The author opens with [device] in order to [function: establish relevance / engage the reader / contextualise the issue], by showing that [paraphrased point linked to main claim]." },
      { label: "Conclusion device", t: "The author concludes by [device/action], in order to [function: summarise / reiterate / call to action / create circularity], reinforcing the argument that [paraphrased main claim]." },
      { label: "2-mark answer", t: "Firstly, the final sentence reiterates the argument that [point 1]. Additionally, it creates a sense of urgency by [point 2]." },
    ],
    eg: {
      passage: 'Question: "What is the purpose of the opening paragraph?" (anecdote about a child using a smartphone)',
      weak: '"The author uses an anecdote to make the passage more interesting." — No function, no link to claim.',
      strong: '"The author opens with an anecdote about a young child using a smartphone to establish the pervasiveness of digital technology, engaging the reader with a relatable scene and contextualising the argument that even the youngest members of society are not immune to the effects of excessive screen time."',
      why: 'Device named (anecdote). Function stated (establish pervasiveness, engage reader). Point linked to main claim (screen time effects on children).',
    },
  },
  {
    id: "q6", code: "Q6", section: "B3", sectionLabel: "Structural", badge: "Attitude · Language · Pronouns",
    title: "Author's Voice", subtitle: "Attitude, use of language, and personal pronouns",
    color: "#17a2b8", bg: "#E0F6F9", emoji: "🎤",
    commandWords: ['"What is the author\'s attitude towards…"', '"Identify the language feature…"', '"Explain the use of \'we\'…"'],
    steps: [
      { n: 1, title: "6A — Author's Attitude", body: "Use precise vocabulary: critical, sceptical, dismissive, cynical, cautious, measured, disapproving, optimistic, hopeful, ambivalent. Avoid vague labels like 'negative'. Structure: 'The word [word] suggests the author is [precise attitude] of [subject], because [contextual explanation].'" },
      { n: 2, title: "6B — Use of Language", body: "Identify the feature: hyperbole, analogy, metaphor, oxymoron, irony, emotionally charged language, loaded diction. For metaphors/analogies — apply Q4C method (literal → contextual). For hyperbole/loaded diction — explain connotation and effect." },
      { n: 3, title: "6C — Personal Pronouns", body: "'You': directly address reader, make them feel implicated. 'We'/'Us': include reader in shared group, build solidarity. 'They'/'Them': distance the author, create us-vs-them. Always explain what the pronoun communicates about that group's situation." },
    ],
    templates: [
      { label: "6A Attitude", t: "The word [word] suggests that the author is [precise attitude word] of [subject], because [contextual explanation of what is implied about the subject]." },
      { label: "6B Language feature", t: "The author uses [language feature] in the phrase [quote] to [function: criticise / reinforce / challenge], suggesting that [paraphrased contextual point — including connotation]." },
      { label: "6C Pronoun 'We'", t: "The author uses 'we' to include the reader as part of a shared group, suggesting collective [responsibility / experience / complicity] in [paraphrased contextual point]." },
    ],
    eg: {
      passage: '"We willingly share our personal views and data online without considering the consequences."',
      weak: '"The author uses \'we\' to include everyone." — No function, no contextual explanation.',
      strong: '"The author uses \'we\' to implicate both himself and the reader as willing participants in the erosion of online privacy, building a sense of collective responsibility and suggesting that the problem is not external but self-inflicted."',
      why: 'Pronoun function (implicate/include reader). Contextual point (collective responsibility, self-inflicted). Both elements present.',
    },
  },
];

const CRITICAL_READING_STEPS = [
  { n: 1, title: "Author's Purpose", q: "Why did the author write this? What effect does the author intend to create?", color: "#216ef4", bg: "#E4EFFE" },
  { n: 2, title: "Claim, POV, Context & Reasons", q: "What is the claim? From what context (cultural, societal)? What reasons/evidence are given?", color: "#6660B9", bg: "#EEEAFF" },
  { n: 3, title: "Assumptions", q: "What assumptions did the author make? Are they valid, fair, and free from bias?", color: "#17a2b8", bg: "#E0F6F9" },
  { n: 4, title: "Readers' Conclusions", q: "What conclusions should the reader draw? Are they justified, balanced, logical, and significant?", color: "#E07800", bg: "#FFF0D9" },
  { n: 5, title: "Implications & Consequences", q: "What are the implications of accepting or rejecting the argument? Are they significant?", color: "#FB424E", bg: "#FFEBEC" },
  { n: 6, title: "Rethink and Question", q: "Would these conclusions change given the possible implications and consequences of accepting the claim?", color: "#6C7A99", bg: "#EEF2FB" },
];

const DISCOURSE_MARKERS = [
  { fn: "Emphasis",        examples: "Indeed, In fact, Importantly, Furthermore, Moreover", color: "#216ef4" },
  { fn: "Contrast / Shift", examples: "However, Rather, In contrast, Conversely, On the other hand", color: "#FB424E" },
  { fn: "Similarity",      examples: "Similarly, Likewise, Also, Again", color: "#17a2b8" },
  { fn: "Clarification",   examples: "In particular, More specifically, With respect to", color: "#6660B9" },
  { fn: "Nuance",          examples: "Although, Even though, Notwithstanding, Yet, Nevertheless", color: "#E07800" },
  { fn: "Cause-Effect",    examples: "Therefore, Hence, Consequently, As a result, Accordingly", color: "#006840" },
  { fn: "Illustration",    examples: "For instance, For example, Namely, Such as", color: "#FF8C3A" },
  { fn: "Summary",         examples: "In conclusion, To summarise, Overall, Finally", color: "#8A96B0" },
];

function QTypeDetail({ qt, showStrong, setShowStrong }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12, padding: "16px 16px 20px", borderTop: `2px solid ${qt.color}22`, animation: "fadeSlideIn 0.2s ease" }}>
      {/* Command words */}
      <div>
        <div style={{ fontSize: 10, fontWeight: 700, color: T.textTer, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 8 }}>Trigger Phrases</div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
          {qt.commandWords.map((w, i) => (
            <span key={i} style={{ background: qt.bg, color: qt.color, padding: "3px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700, border: `1px solid ${qt.color}33` }}>{w}</span>
          ))}
        </div>
      </div>

      {/* Steps */}
      <div>
        <div style={{ fontSize: 10, fontWeight: 700, color: T.textTer, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 10 }}>The Approach</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {qt.steps.map((s, i) => (
            <div key={i} style={{ display: "flex", gap: 12 }}>
              <div style={{ width: 24, height: 24, borderRadius: "50%", background: qt.color, color: "#fff", fontSize: 12, fontWeight: 800, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1 }}>{s.n}</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 12, color: T.text, marginBottom: 2 }}>{s.title}</div>
                <div style={{ fontSize: 12, color: T.textSec, lineHeight: 1.6 }}>{s.body}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Templates */}
      <div>
        <div style={{ fontSize: 10, fontWeight: 700, color: T.textTer, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 8 }}>Answer Templates</div>
        {qt.templates.map((tmpl, i) => (
          <div key={i} style={{ marginBottom: 8 }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: qt.color, marginBottom: 4 }}>{tmpl.label}</div>
            <div style={{ background: qt.bg, border: `1px solid ${qt.color}33`, borderRadius: T.r1, padding: "8px 12px", fontSize: 12, color: T.text, lineHeight: 1.7, fontStyle: "italic" }}>{tmpl.t}</div>
          </div>
        ))}
      </div>

      {/* Worked example */}
      <div>
        <div style={{ fontSize: 10, fontWeight: 700, color: T.textTer, textTransform: "uppercase", letterSpacing: 0.8, marginBottom: 8 }}>Worked Example</div>
        <div style={{ background: T.bgMuted, borderRadius: T.r1, padding: "8px 12px", fontSize: 12, color: T.text, marginBottom: 10, lineHeight: 1.6 }}>
          <span style={{ fontWeight: 700, color: T.textSec }}>Passage: </span>{qt.eg.passage}
        </div>
        <div style={{ display: "flex", gap: 0, background: T.bgMuted, borderRadius: T.r1, padding: 3, marginBottom: 10, width: "fit-content" }}>
          <button onClick={() => setShowStrong(false)} style={{ padding: "4px 12px", borderRadius: 7, border: "none", background: !showStrong ? "#FB424E" : "transparent", color: !showStrong ? "#fff" : T.textSec, fontSize: 11, fontWeight: 700, cursor: "pointer", transition: "all 0.15s" }}>✗ Weak</button>
          <button onClick={() => setShowStrong(true)} style={{ padding: "4px 12px", borderRadius: 7, border: "none", background: showStrong ? "#17a2b8" : "transparent", color: showStrong ? "#fff" : T.textSec, fontSize: 11, fontWeight: 700, cursor: "pointer", transition: "all 0.15s" }}>✓ Strong</button>
        </div>
        <div style={{ background: showStrong ? "#E0F6F9" : "#FFEBEC", border: `1px solid ${showStrong ? "#17a2b8" : "#FB424E"}44`, borderRadius: T.r1, padding: "10px 12px", fontSize: 12, color: T.text, lineHeight: 1.7, marginBottom: showStrong ? 8 : 0, transition: "background 0.25s" }}>
          {showStrong ? qt.eg.strong : qt.eg.weak}
        </div>
        {showStrong && (
          <div style={{ background: "#E4EFFE", borderRadius: T.r1, padding: "8px 12px", fontSize: 11, color: "#1250B0", lineHeight: 1.6 }}>
            <span style={{ fontWeight: 700 }}>Why it works: </span>{qt.eg.why}
          </div>
        )}
      </div>
    </div>
  );
}

function GP2Infographic() {
  const [selected, setSelected] = useState(null);
  const [showStrong, setShowStrong] = useState(false);
  const [animBars, setAnimBars] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setAnimBars(true), 100);
    return () => clearTimeout(t);
  }, []);

  const sectionGroups = [
    { label: "Section A — Literal Paraphrasing", color: "#216ef4", items: GP2_QTYPES.filter(q => q.section === "A") },
    { label: "Section B1 — Word & Phrase Level", color: "#6660B9", items: GP2_QTYPES.filter(q => q.section === "B1") },
    { label: "Section B2 — Device & Figure Level", color: "#6660B9", items: GP2_QTYPES.filter(q => q.section === "B2") },
    { label: "Section B3 — Structural & Authorial", color: "#17a2b8", items: GP2_QTYPES.filter(q => q.section === "B3") },
  ];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {/* Paper 2 at a glance */}
      <div style={{ background: "linear-gradient(120deg, #0F1B3D 0%, #1A2A5E 60%, #216ef4 100%)", borderRadius: T.r3, padding: "20px 22px", color: "#fff" }}>
        <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", color: "#8BAEED", marginBottom: 4 }}>A-Level H1 General Paper · 8881</div>
        <div style={{ fontSize: 20, fontWeight: 800, fontFamily: "'Bricolage Grotesque', sans-serif", marginBottom: 16 }}>Paper 2 · 90 Minutes · 50 Marks</div>
        {GP2_OVERVIEW.map(c => (
          <div key={c.code} style={{ marginBottom: 8 }}>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, marginBottom: 3 }}>
              <span style={{ color: "#C8D8F5", fontWeight: 600 }}>{c.code} — {c.label}</span>
              <span style={{ color: "#fff", fontWeight: 700 }}>{c.marks} marks · {c.time}</span>
            </div>
            <div style={{ height: 5, background: "rgba(255,255,255,0.1)", borderRadius: 8, overflow: "hidden" }}>
              <div style={{ height: "100%", background: c.color, borderRadius: 8, width: animBars ? `${c.pct * 4}%` : "0%", transition: "width 1s cubic-bezier(0.4,0,0.2,1)", maxWidth: "100%" }} />
            </div>
          </div>
        ))}
      </div>

      {/* Accordion question types */}
      <div style={{ fontSize: 13, fontWeight: 600, color: T.textSec }}>Click any question type below to see the full approach, templates, and worked examples.</div>

      {sectionGroups.map(grp => (
        <div key={grp.label}>
          <div style={{ fontSize: 11, fontWeight: 700, color: grp.color, letterSpacing: 0.8, textTransform: "uppercase", marginBottom: 8, paddingLeft: 2 }}>{grp.label}</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            {grp.items.map(qt => {
              const isOpen = selected === qt.id;
              return (
                <div key={qt.id} style={{ borderRadius: T.r2, border: `2px solid ${isOpen ? qt.color : T.border}`, background: isOpen ? qt.bg : T.bgCard, overflow: "hidden", transition: "border-color 0.18s, background 0.18s", boxShadow: isOpen ? `0 0 0 3px ${qt.color}18` : "none" }}>
                  <button onClick={() => { setSelected(s => s === qt.id ? null : qt.id); setShowStrong(false); }}
                    style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 14px", width: "100%", background: "none", border: "none", cursor: "pointer", textAlign: "left" }}>
                    <div style={{ fontSize: 22, flexShrink: 0 }}>{qt.emoji}</div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 2 }}>
                        <span style={{ fontSize: 11, fontWeight: 800, color: qt.color, fontFamily: "'JetBrains Mono', monospace" }}>{qt.code}</span>
                        <span style={{ fontSize: 10, fontWeight: 700, color: qt.color, background: isOpen ? "#fff" : qt.bg, padding: "1px 6px", borderRadius: 20 }}>{qt.badge}</span>
                      </div>
                      <div style={{ fontSize: 13, fontWeight: 700, color: T.text }}>{qt.title}</div>
                      <div style={{ fontSize: 11, color: T.textSec, marginTop: 1 }}>{qt.subtitle}</div>
                    </div>
                    <CaretDown size={15} color={qt.color} style={{ transform: isOpen ? "rotate(180deg)" : "none", transition: "transform 0.2s", flexShrink: 0 }} />
                  </button>
                  {isOpen && <QTypeDetail qt={qt} showStrong={showStrong} setShowStrong={setShowStrong} />}
                </div>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

function CriticalReadingInfographic() {
  const [active, setActive] = useState(null);
  const [dmAnim, setDmAnim] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setDmAnim(true), 200);
    return () => clearTimeout(t);
  }, []);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      {/* Hero */}
      <div style={{ background: "linear-gradient(120deg, #0F1B3D, #216ef4)", borderRadius: T.r3, padding: "22px 26px", color: "#fff" }}>
        <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", color: "#8BAEED", marginBottom: 6 }}>Foundation Skill · All Question Types</div>
        <div style={{ fontSize: 22, fontWeight: 800, fontFamily: "'Bricolage Grotesque', sans-serif", marginBottom: 6 }}>Critical Reading Framework</div>
        <div style={{ fontSize: 13, color: "#C8D8F5", lineHeight: 1.6 }}>Critical reading means analysing underlying meaning, evaluating the author's intentions and assumptions, and forming a reasoned response — not simply retaining information. Apply these 6 steps to every passage.</div>
      </div>

      {/* 6-step flow */}
      <div>
        <div style={{ fontSize: 13, fontWeight: 700, color: T.textSec, marginBottom: 12 }}>The 6-Step Critical Reading Routine — click any step to expand</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {CRITICAL_READING_STEPS.map(step => (
            <div key={step.n} onClick={() => setActive(a => a === step.n ? null : step.n)}
              style={{ borderRadius: T.r2, border: `2px solid ${active === step.n ? step.color : T.border}`, background: active === step.n ? step.bg : T.bgCard, cursor: "pointer", overflow: "hidden", transition: "all 0.2s" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px" }}>
                <div style={{ width: 34, height: 34, borderRadius: "50%", background: step.color, color: "#fff", fontWeight: 800, fontSize: 15, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>{step.n}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 13, color: T.text }}>Step {step.n} — {step.title}</div>
                  {active !== step.n && <div style={{ fontSize: 11, color: T.textSec, marginTop: 2, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{step.q}</div>}
                </div>
                <CaretDown size={14} color={step.color} style={{ transform: active === step.n ? "rotate(180deg)" : "none", transition: "transform 0.2s", flexShrink: 0 }} />
              </div>
              {active === step.n && (
                <div style={{ padding: "0 16px 16px 64px" }}>
                  <div style={{ background: "#fff", borderRadius: T.r1, padding: "12px 14px", fontSize: 13, color: T.text, lineHeight: 1.7, border: `1px solid ${step.color}33` }}>
                    <span style={{ fontWeight: 700, color: step.color }}>Key question: </span>{step.q}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Discourse markers */}
      <div>
        <div style={{ fontSize: 13, fontWeight: 700, color: T.textSec, marginBottom: 12 }}>Common Discourse Markers — Quick Reference</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))", gap: 10 }}>
          {DISCOURSE_MARKERS.map((dm, i) => (
            <div key={i} style={{ background: T.bgCard, borderRadius: T.r2, padding: "12px 14px", border: `1px solid ${T.border}`, borderLeft: `4px solid ${dm.color}`, opacity: dmAnim ? 1 : 0, transform: dmAnim ? "translateY(0)" : "translateY(12px)", transition: `opacity 0.4s ease ${i * 0.05}s, transform 0.4s ease ${i * 0.05}s` }}>
              <div style={{ fontSize: 11, fontWeight: 800, color: dm.color, textTransform: "uppercase", letterSpacing: 0.6, marginBottom: 5 }}>{dm.fn}</div>
              <div style={{ fontSize: 12, color: T.textSec, lineHeight: 1.5 }}>{dm.examples}</div>
            </div>
          ))}
        </div>
      </div>

      {/* APT reminder */}
      <div style={{ background: T.accentLight, borderRadius: T.r2, padding: "14px 18px", border: `1px solid ${T.accentMid}`, display: "flex", gap: 14, alignItems: "flex-start" }}>
        <Sparkle size={18} weight="fill" color={T.accent} style={{ flexShrink: 0, marginTop: 2 }} />
        <div>
          <div style={{ fontWeight: 700, fontSize: 13, color: T.accentText, marginBottom: 4 }}>APT Paraphrasing — The Golden Rule</div>
          <div style={{ display: "flex", gap: 20, flexWrap: "wrap" }}>
            {[["Accuracy","Replace words with synonyms of the same connotation in context."],["Precision","Capture the intensity and nuance. Do not water down strong language."],["Thoroughness","Capture the complete idea: context, cause-effect, specific subject."]].map(([k,v]) => (
              <div key={k} style={{ minWidth: 160 }}>
                <span style={{ fontWeight: 700, color: T.accent }}>{k}: </span>
                <span style={{ fontSize: 12, color: T.accentText }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

